// Define the I2C address of the Si1133 sensor
#define SI1133_I2C_ADDR 0x60

// Define register addresses for UV index, ALS, and IR data
#define SI1133_REG_UVINDEX 0x2C
#define SI1133_REG_ALS_VIS 0x22
#define SI1133_REG_IR      0x24

// Global variables
int fd;                // I2C file descriptor
FILE *log_file;       // File pointer for the log file
volatile sig_atomic_t program_running = 1; // Flag to control the main loop

// Signal handler for graceful shutdown
void signal_handler(int sig) {
    fprintf(stderr, "\nCaught signal %d, exiting gracefully.\n", sig);
    program_running = 0;
}

// Function to initialize the Si1133 sensor
int init_si1133() {
    fd = wiringPiI2CSetup(SI1133_I2C_ADDR);
    if (fd == -1) {
        perror("wiringPiI2CSetup failed");
        fprintf(stderr, "Failed to initialize Si1133 sensor.\n");
        return -1;
    }
    printf("Si1133 sensor initialized successfully.\n");
    return 0;
}

// Function to read a 16-bit register from the Si1133 sensor
uint16_t read_si1133_register(int reg) {
    int result = wiringPiI2CReadReg16(fd, reg);
    if (result == -1) {
        perror("wiringPiI2CReadReg16 failed");
        fprintf(stderr, "Failed to read register 0x%02X.\n", reg);
        return 0; // Return 0 on error
    }
    return (uint16_t)result;
}

// Function to format the sensor data and timestamp into a log string
char* format_log_string(uint16_t uv_index, uint16_t als, uint16_t ir) {
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    static char timestamp[64]; // Static to preserve across calls
    strftime(timestamp, sizeof(timestamp)-1, "%Y-%m-%d %H:%M:%S", t);

    static char log_string[256]; // Static to preserve across calls
    snprintf(log_string, sizeof(log_string)-1, "%s, UV Index: %u, ALS: %u, IR: %u\n", timestamp, uv_index, als, ir);
    return log_string;
}

// Function to write the log string to the file
int write_to_log_file(const char *log_string) {
    if (log_file == NULL) {
        fprintf(stderr, "Log file is not open.\n");
        return -1;
    }
    if (fprintf(log_file, "%s", log_string) < 0) {
        perror("fprintf failed");
        fprintf(stderr, "Failed to write to log file.\n");
        return -1;
    }
    fflush(log_file); // Flush the buffer to ensure data is written immediately
    return 0;
}

int main() {
    // Set up signal handling for Ctrl+C
    signal(SIGINT, signal_handler);

    // Open the log file
    log_file = fopen("light_data.log", "a");
    if (log_file == NULL) {
        perror("fopen failed");
        fprintf(stderr, "Failed to open log file.\n");
        return 1;
    }

    // Initialize the Si1133 sensor
    if (init_si1133() == -1) {
        fclose(log_file);
        return 1;
    }

    // Main loop to continuously read sensor data and log it
    while (program_running) {
        // Read sensor data
        uint16_t uv_index = read_si1133_register(SI1133_REG_UVINDEX);
        uint16_t als      = read_si1133_register(SI1133_REG_ALS_VIS);
        uint16_t ir       = read_si1133_register(SI1133_REG_IR);

        // Format the log string
        char *log_string = format_log_string(uv_index, als, ir);

        // Write to the log file
        if (write_to_log_file(log_string) == -1) {
            // Log the error to stderr as well
            fprintf(stderr, "Failed to write log data: %s", log_string);
        }

        // Sleep for 1 second
        delay(1000);
    }

    // Close the log file before exiting
    fclose(log_file);
    printf("Program finished.\n");
    return 0;
}

