#define REG_IRQ_MODE1 0x04
#define REG_ALS_IR_THR0 0x10
#define REG_ALS_IR_THR1 0x11
#define REG_ALS_VIS_THR0 0x12
#define REG_ALS_VIS_THR1 0x13


// Function to read a register
int readRegister(int fd, uint8_t reg)
{
    int result = wiringPiI2CReadReg8(fd, reg);
    if (result == -1)
    {
        fprintf(stderr, "Error reading register 0x%02X: %s\n", reg, strerror(errno));
        return -1; // Indicate error
    }
    return result;
}

// Function to write a register
int writeRegister(int fd, uint8_t reg, uint8_t value)
{
    int result = wiringPiI2CWriteReg8(fd, reg, value);
    if (result == -1)
    {
        fprintf(stderr, "Error writing register 0x%02X: %s\n", reg, strerror(errno));
        return -1; // Indicate error
    }
    return 0;
}

// Function to read a 16-bit value from two registers
int read16(int fd, uint8_t reg)
{
    int low = readRegister(fd, reg);
    int high = readRegister(fd, reg + 1);

    if (low == -1 || high == -1) {
        return -1; // Propagate error
    }

    return (high << 8) | low;
}

