#define POLLING_INTERVAL_MS 500 // Temperature polling interval (milliseconds)
#define CIRCULAR_BUFFER_SIZE 100 // Size of the circular buffer

// Global variables
int i2c_fd;
volatile sig_atomic_t program_running = 1;

// Circular buffer structure
typedef struct {
    float temperature;
    int fan_speed;
    time_t timestamp;
} log_entry_t;

log_entry_t circular_buffer[CIRCULAR_BUFFER_SIZE];
