// Function to generate a tone on a GPIO pin
void generate_tone(int pin, int frequency)
{
    if (frequency > 0)
    {
        int period = 1000000 / frequency; // Period in microseconds
        gpioWaveClear();

        gpioWaveAddPulse(gpioPulse(pin, 0, period / 2));
        gpioWaveAddPulse(gpioPulse(0, pin, period / 2));

        int wave_id = gpioWaveCreate();
        if (wave_id >= 0)
        {
            gpioWaveTxSend(wave_id, PI_WAVE_MODE_LOOP);
        } else {
            fprintf(stderr, "Error creating wave: %d\n", wave_id);
        }
    } else {
