// Callback function for PIR sensor interrupt
void pir_callback(int gpio, int level, uint32_t tick) {
    int current_time = gpioTime();

    // Debounce the signal
    if (current_time - last_interrupt_time > DEBOUNCE_TIME * 1000) {
