#define SHT31_ADDR 0x44

// SHT31-D commands
#define MEAS_HIGHREP 0x2C06 // Measurement command, High Repeatability

// Function to read temperature and humidity from SHT31-D
int read_sht31(int fd, float *temperature, float *humidity) {
    uint8_t buf[6];
    int ret;

    // Send measurement command
    buf[0] = (MEAS_HIGHREP >> 8) & 0xFF;
    buf[1] = MEAS_HIGHREP & 0xFF;
    ret = write(fd, buf, 2);
    if (ret != 2) {
        fprintf(stderr, "Error writing to I2C device: %s\n", strerror(errno));
        return -1;
    }

    // Wait for measurement to complete (typical 10ms, max 15ms)
    usleep(20000); // 20ms

    // Read 6 bytes of data (Temp MSB, Temp LSB, Temp CRC, Humid MSB, Humid LSB, Humid CRC)
    ret = read(fd, buf, 6);
    if (ret != 6) {
        fprintf(stderr, "Error reading from I2C device: %s\n", strerror(errno));
        return -1;
    }

    // Convert data
    int temperature_raw = (buf[0] << 8) | buf[1];
    int humidity_raw = (buf[3] << 8) | buf[4];

    // Convert to Celsius and %RH
    *temperature = -45.0 + (175.0 * (float)temperature_raw / 65535.0);
    *humidity = 100.0 * (float)humidity_raw / 65535.0;

    return 0;
}

int main() {
    int fd;
    float temperature, humidity;
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    // Initialize wiringPi I2C
    if ((fd = wiringPiI2CSetup(SHT31_ADDR)) < 0) {
        fprintf(stderr, "Unable to initialize I2C: %s\n", strerror(errno));
        return 1;
    }

    // Create JSON object
    json_t *root = json_object();
    json_t *data_array = json_array();

    // Main loop
    for (int i = 0; i < 10; ++i) {
