void logData(float temperature, int fanSpeed);

int main()
{
    int fd;
    float temperature;
    int fanSpeed = 0;

    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "wiringPiSetupGpio failed: %s\n", strerror(errno));
        return 1;
    }

    // Initialize I2C
    fd = wiringPiI2CSetup(LM75_ADDRESS);
    if (fd == -1) {
        fprintf(stderr, "wiringPiI2CSetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Initialize PWM
    softPwmCreate(PWM_PIN, 0, 100); // PWM range: 0-100

    // Main loop
    while (1) {
        // Read temperature
        temperature = readTemperature(fd);

        // Adjust fan speed based on temperature
        if (temperature > 50.0) {
            fanSpeed = 100;
        } else if (temperature > 40.0) {
            fanSpeed = 50;
        } else {
            fanSpeed = 0;
        }

        // Set fan speed
        setFanSpeed(fanSpeed);

        // Log data
        logData(temperature, fanSpeed);

        // Wait for a while
        delay(5000); // Check every 5 seconds
    }

    return 0;
}

// Function to read temperature from LM75 sensor
float readTemperature(int fd)
{
    int16_t rawTemperature;
    float temperature;

    // Read temperature registers (2 bytes)
    rawTemperature = wiringPiI2CReadReg16(fd, 0); // Read from temperature register
    if (rawTemperature == -1) {
        fprintf(stderr, "Error reading temperature: %s\n", strerror(errno));
        return -273.15; // Return absolute zero on error
    }

    // Convert raw temperature to Celsius (LM75B datasheet)
    // The LM75 returns a 11-bit signed integer, left-aligned.
    // We need to shift it right by 5 bits to get the correct value.
    rawTemperature = (rawTemperature << 5) >> 5; // Sign extend and shift
    temperature = (float)rawTemperature / 8.0;

    return temperature;
}

// Function to set fan speed using PWM
void setFanSpeed(int speed)
{
    softPwmWrite(PWM_PIN, speed);
}

// Function to log temperature and fan speed to a file
void logData(float temperature, int fanSpeed)
{
    FILE *fp;
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);

    fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        return;
    }

    fprintf(fp, "%d-%02d-%02d %02d:%02d:%02d, Temperature: %.2f C, Fan Speed: %d%%\n",
            tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec,
            temperature, fanSpeed);

    fclose(fp);
}

