// VL53L1X defines
#define VL53L1X_DEFAULT_ADDRESS 0x29
#define VL53L1X_REG_IDENTIFICATION_MODEL_ID 0x010F
#define VL53L1X_REG_IDENTIFICATION_REVISION_ID 0x0110
#define VL53L1X_REG_SYSRANGE_START 0x000
#define VL53L1X_REG_RESULT_RANGE_STATUS 0x004D
#define VL53L1X_REG_RESULT_FINAL_CROSSTALK_CORRECTED_RANGE_MM_SD0 0x0050

// Threshold for proximity warning (in mm)
#define PROXIMITY_THRESHOLD 200

// I2C file descriptor
int fd;

// Function to write a byte to a VL53L1X register
int vl53l1x_write_byte(int reg, uint8_t value) {
  if (wiringPiI2CWriteReg8(fd, reg, value) < 0) {
    fprintf(stderr, "Error writing to register 0x%02X: %s\n", reg, strerror(errno));
    return -1;
  }
  return 0;
}

// Function to read a byte from a VL53L1X register
int vl53l1x_read_byte(int reg, uint8_t *value) {
  int result = wiringPiI2CReadReg8(fd, reg);
  if (result < 0) {
    fprintf(stderr, "Error reading from register 0x%02X: %s\n", reg, strerror(errno));
    return -1;
  }
  *value = (uint8_t)result;
  return 0;
}

// Function to read a word (2 bytes) from a VL53L1X register
int vl53l1x_read_word(int reg, uint16_t *value) {
  int high_byte, low_byte;

  high_byte = wiringPiI2CReadReg8(fd, reg);
  low_byte = wiringPiI2CReadReg8(fd, reg + 1);

  if (high_byte < 0 || low_byte < 0) {
    fprintf(stderr, "Error reading word from register 0x%02X: %s\n", reg, strerror(errno));
    return -1;
  }

  *value = (uint16_t)((high_byte << 8) | low_byte);
  return 0;
}

// Function to initialize the VL53L1X sensor
int vl53l1x_init() {
  uint8_t model_id, revision_id;

  // Check the sensor ID
  if (vl53l1x_read_byte(VL53L1X_REG_IDENTIFICATION_MODEL_ID, &model_id) < 0) return -1;
  if (vl53l1x_read_byte(VL53L1X_REG_IDENTIFICATION_REVISION_ID, &revision_id) < 0) return -1;

  if (model_id != 0xEA) {
    fprintf(stderr, "Error: Invalid sensor ID (Model ID: 0x%02X, Revision ID: 0x%02X)\n", model_id, revision_id);
    return -1;
  }

  // Recommended settings from ST application note AN5352
  if (vl53l1x_write_byte(0x02D8, 0x01) < 0) return -1;
  if (vl53l1x_write_byte(0x02DA, 0x01) < 0) return -1;
  if (vl53l1x_write_byte(0x02E8, 0x01) < 0) return -1;
  if (vl53l1x_write_byte(0x0300, 0x01) < 0) return -1;
  if (vl53l1x_write_byte(0x0302, 0x01) < 0) return -1;

  // Start continuous ranging
  if (vl53l1x_write_byte(VL53L1X_REG_SYSRANGE_START, 0x04) < 0) return -1;

  return 0;
}

// Function to read the distance from the VL53L1X sensor
int vl53l1x_read_distance(uint16_t *distance) {
  uint8_t range_status;
  uint16_t raw_distance;

  // Wait for a new measurement to be ready (crude method)
delay(5);

  if (vl53l1x_read_byte(VL53L1X_REG_RESULT_RANGE_STATUS, &range_status) < 0) return -1;

  if (vl53l1x_read_word(VL53L1X_REG_RESULT_FINAL_CROSSTALK_CORRECTED_RANGE_MM_SD0, &raw_distance) < 0) return -1;

  *distance = raw_distance;

  return 0;
}

int main() {
  FILE *log_file;
  time_t rawtime;
  struct tm *timeinfo;
  uint16_t distance;

  // Initialize wiringPi
  if (wiringPiSetup() == -1) {
    fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
    return 1;
  }

  // Open I2C device
  fd = wiringPiI2CSetup(VL53L1X_DEFAULT_ADDRESS);
  if (fd == -1) {
    fprintf(stderr, "I2C setup failed: %s\n", strerror(errno));
    return 1;
  }

  // Initialize the VL53L1X sensor
  if (vl53l1x_init() < 0) {
    fprintf(stderr, "VL53L1X initialization failed.\n");
    return 1;
  }

  // Open the log file
  log_file = fopen("distance_log.txt", "a");
  if (log_file == NULL) {
    fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
    return 1;
  }

  printf("VL53L1X sensor initialized.  Reading distances...\n");

  while (1) {
    // Read the distance
    if (vl53l1x_read_distance(&distance) == 0) {
      // Get current timestamp
      time(&rawtime);
      timeinfo = localtime(&rawtime);
      char timestamp[26];
      strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

      // Log the timestamp and distance to the file
      fprintf(log_file, "%s, %d\n", timestamp, distance);
      fflush(log_file); // Ensure data is written to disk immediately

      printf("Distance: %d mm\n", distance);

      // Check for proximity warning
      if (distance < PROXIMITY_THRESHOLD) {
        printf("WARNING: Object closer than %d mm!\n", PROXIMITY_THRESHOLD);
      }
    } else {
      fprintf(stderr, "Error reading distance.\n");
    }

    delay(100); // Delay between readings
  }

  // Close the log file (this will likely never be reached in this example)
  fclose(log_file);

  return 0;
}

