// LSM303D I2C address
#define LSM303D_ADDR 0x1D

// LSM303D registers
#define CTRL1_REG 0x20
#define CTRL2_REG 0x21
#define CTRL3_REG 0x22
#define CTRL4_REG 0x23
#define CTRL5_REG 0x24
#define CTRL6_REG 0x25
#define CTRL7_REG 0x26
#define OUT_X_L_A 0x28
#define OUT_X_H_A 0x29
#define OUT_Y_L_A 0x2A
#define OUT_Y_H_A 0x2B
#define OUT_Z_L_A 0x2C
#define OUT_Z_H_A 0x2D

// LED GPIO pin
#define LED_PIN 17

// Acceleration threshold (1.5g)
#define ACCEL_THRESHOLD 1.5f

// Earth's gravity in m/s^2
#define EARTH_GRAVITY_MS2 9.80665f

// Function to read a single byte from an I2C register
int readRegister(int fd, uint8_t reg)
{
  int result = wiringPiI2CReadReg8(fd, reg);
  if (result == -1) {
    fprintf(stderr, "Error reading register 0x%02X: %s\n", reg, strerror(errno));
    return -1;
  }
  return result;
}

// Function to write a single byte to an I2C register
int writeRegister(int fd, uint8_t reg, uint8_t value)
{
  int result = wiringPiI2CWriteReg8(fd, reg, value);
  if (result == -1) {
    fprintf(stderr, "Error writing register 0x%02X: %s\n", reg, strerror(errno));
    return -1;
  }
  return 0;
}

// Function to initialize the LSM303D accelerometer
bool initLSM303D(int fd)
{
  // Enable accelerometer (100Hz, normal mode)
  if (writeRegister(fd, CTRL1_REG, 0x67) == -1) return false; // ODR = 100 Hz, Enable X, Y, Z axes
  if (writeRegister(fd, CTRL2_REG, 0x00) == -1) return false; // +/- 2g range
  if (writeRegister(fd, CTRL3_REG, 0x00) == -1) return false; // Interrupt disabled
  if (writeRegister(fd, CTRL4_REG, 0x00) == -1) return false; // Block data update disabled, little endian
  return true;
}

// Function to read acceleration data from the LSM303D
bool readAcceleration(int fd, float *x, float *y, float *z)
{
  int16_t rawX, rawY, rawZ;
  int xL, xH, yL, yH, zL, zH;

  // Read raw acceleration data
  xL = readRegister(fd, OUT_X_L_A);
  xH = readRegister(fd, OUT_X_H_A);
  yL = readRegister(fd, OUT_Y_L_A);
  yH = readRegister(fd, OUT_Y_H_A);
  zL = readRegister(fd, OUT_Z_L_A);
  zH = readRegister(fd, OUT_Z_H_A);

  if (xL == -1 || xH == -1 || yL == -1 || yH == -1 || zL == -1 || zH == -1) {
    return false;
  }

  // Combine high and low bytes (LITTLE ENDIAN)
  rawX = (int16_t)((xH << 8) | xL);
  rawY = (int16_t)((yH << 8) | yL);
  rawZ = (int16_t)((zH << 8) | zL);

  // Convert to g (assuming +/- 2g range, sensitivity = 1 mg/LSB)
  *x = (float)rawX / 16384.0f;
  *y = (float)rawY / 16384.0f;
  *z = (float)rawZ / 16384.0f;

  return true;
}

int main()
{
  int fd;
  float x, y, z, magnitude;

  // Initialize wiringPi
  if (wiringPiSetupGpio() == -1) {
    fprintf(stderr, "wiringPiSetupGpio failed: %s\n", strerror(errno));
    return 1;
  }

  // Initialize I2C
  fd = wiringPiI2CSetup(LSM303D_ADDR);
  if (fd == -1) {
    fprintf(stderr, "wiringPiI2CSetup failed: %s\n", strerror(errno));
    return 1;
  }

  // Initialize LSM303D
  if (!initLSM303D(fd)) {
    fprintf(stderr, "LSM303D initialization failed.\n");
    return 1;
  }

  // Set LED pin as output
  pinMode(LED_PIN, OUTPUT);

  printf("Reading acceleration data...\n");

  while (1) {
    // Read acceleration data
    if (readAcceleration(fd, &x, &y, &z)) {
      // Calculate magnitude of acceleration
      magnitude = sqrt(x * x + y * y + z * z);

      printf("X: %.3f g, Y: %.3f g, Z: %.3f g, Magnitude: %.3f g\n", x, y, z, magnitude);

      // Check if acceleration exceeds threshold
      if (magnitude > ACCEL_THRESHOLD) {
        digitalWrite(LED_PIN, HIGH); // Turn LED on
        printf("Acceleration threshold exceeded! LED ON\n");
      } else {
        digitalWrite(LED_PIN, LOW);  // Turn LED off
      }
    } else {
      fprintf(stderr, "Failed to read acceleration data.\n");
    }

    delay(100); // Delay 100ms
  }

  return 0;
}

