}

int read_mcp3008(int channel)
{
    int handle = spiOpen(SPI_CHANNEL, SPI_SPEED, 0); // Mode 0
    if (handle < 0) {
        fprintf(stderr, "SPI open failed: %d\n", handle);
        return -1; // Indicate error
    }

    unsigned char tx_buffer[3];
    unsigned char rx_buffer[3];

    tx_buffer[0] = 0x01; // Start bit
    tx_buffer[1] = ((channel & 0x07) << 4) | 0x80; // Single-ended mode, channel select
    tx_buffer[2] = 0x00;

    if (spiXfer(handle, tx_buffer, rx_buffer, 3) == 3) {
        int adc_value = ((rx_buffer[1] & 0x03) << 8) + rx_buffer[2];
        spiClose(handle);
        return adc_value;
    } else {
        fprintf(stderr, "SPI transfer failed\n");
        spiClose(handle);
        return -1; // Indicate error
    }
}

void activate_relay(int relay_pin, int zone_number)
{
    printf("Activating relay for zone %d (GPIO %d)\n", zone_number, relay_pin);
    gpioWrite(relay_pin, 0); // Assuming LOW is ON
    time_t start_time = time(NULL);

