void deactivate_relay(int relay_pin, int zone_number)
{
    printf("Deactivating relay for zone %d (GPIO %d)\n", zone_number, relay_pin);
    gpioWrite(relay_pin, 1); // Assuming HIGH is OFF
    time_t end_time = time(NULL);

    // Update log with end time
    log_activation(zone_number, 0, end_time); // Log end time only
