    FILE *fp = fopen(LOG_FILE, "a+");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        return;
    }

    fseek(fp, 0, SEEK_END);
    long file_size = ftell(fp);

    char timestamp_str[30];
    struct tm *tm_info;

    if (start_time != 0) {
        tm_info = localtime(&start_time);
        strftime(timestamp_str, sizeof(timestamp_str), "%Y-%m-%d %H:%M:%S", tm_info);

        if (file_size == 0) {
            fprintf(fp, "{\n  \"irrigation_events\": [
    {\n      \"timestamp\": \"%s\",\n      \"zone\": %d,\n      \"status\": \"start\"\n    }
", timestamp_str, zone_number);
        } else {
            fseek(fp, file_size - 2, SEEK_SET); // Move before the last ]
            fprintf(fp, ",\n    {\n      \"timestamp\": \"%s\",\n      \"zone\": %d,\n      \"status\": \"start\"\n    }
", timestamp_str, zone_number);
            fseek(fp, file_size, SEEK_SET);
        }
    } else if (end_time != 0) {
        tm_info = localtime(&end_time);
        strftime(timestamp_str, sizeof(timestamp_str), "%Y-%m-%d %H:%M:%S", tm_info);

        fseek(fp, file_size - 2, SEEK_SET);
        fprintf(fp, ",\n    {\n      \"timestamp\": \"%s\",\n      \"zone\": %d,\n      \"status\": \"end\"\n    }
", timestamp_str, zone_number);
        fseek(fp, file_size, SEEK_SET);
    }

    if (start_time == 0 && end_time == 0 && file_size == 0) {
