    int head;
    int tail;
    int count;
    pthread_mutex_t mutex;
} CircularBuffer;

CircularBuffer vibrationBuffer;
int vibrationThreshold = 0; // Default value, will be set from command line

// Function to initialize the circular buffer
void initCircularBuffer(CircularBuffer *buffer) {
    buffer->head = 0;
    buffer->tail = 0;
    buffer->count = 0;
    pthread_mutex_init(&buffer->mutex, NULL);
}

// Function to add a timestamp to the circular buffer
void addToCircularBuffer(CircularBuffer *buffer, time_t timestamp) {
    pthread_mutex_lock(&buffer->mutex);
    buffer->timestamp[buffer->head] = timestamp;
    buffer->head = (buffer->head + 1) % BUFFER_SIZE;
    if (buffer->count == BUFFER_SIZE) {
        buffer->tail = (buffer->tail + 1) % BUFFER_SIZE;
    } else {
        buffer->count++;
    }
    pthread_mutex_unlock(&buffer->mutex);
}

// Function to dump the circular buffer to a file
void dumpBufferToFile(CircularBuffer *buffer, const char *filename) {
    FILE *fp = fopen(filename, "a"); // Append mode
    if (fp == NULL) {
        perror("Error opening file");
        return;
    }

    pthread_mutex_lock(&buffer->mutex);
    int i = buffer->tail;
    int count = buffer->count;
    while (count > 0) {
        char time_str[30];
        struct tm *tm_info = localtime(&buffer->timestamp[i]);
        strftime(time_str, sizeof(time_str), "%Y-%m-%d %H:%M:%S", tm_info);
        fprintf(fp, "%s\n", time_str);
        i = (i + 1) % BUFFER_SIZE;
        count--;
    }
    pthread_mutex_unlock(&buffer->mutex);

    fclose(fp);
}

