        sensors[i].distance = 0; // Initialize distance
        sensors[i].valid_reading = 0; // Initialize valid_reading flag
    }

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        free(sensors);
        return 1;
    }

    // Open I2C bus
    i2c_bus_handle = i2cOpen(1, 0, 0); // I2C bus 1, address 0 (not used here but required)
    if (i2c_bus_handle < 0) {
        fprintf(stderr, "Failed to open I2C bus\n");
        gpioTerminate();
        free(sensors);
        return 1;
    }

    // Initialize gate control pin
    gpioSetMode(GATE_CONTROL_PIN, PI_OUTPUT);
    control_gate(GATE_CLOSED); // Ensure gate is closed at startup

    // Initialize log file
    log_file = fopen("gate_log.txt", "a");
    if (log_file == NULL) {
        perror("Failed to open log file");
        i2cClose(i2c_bus_handle);
        gpioTerminate();
        free(sensors);
        return 1;
    }

    // Initialize sensors
    for (int i = 0; i < num_sensors; i++) {
        if (init_sensor(&sensors[i]) != 0) {
            fprintf(stderr, "Failed to initialize sensor at address 0x%02X\n", sensors[i].i2c_address);
            // Consider handling sensor failure more gracefully (e.g., disabling the sensor)
        }
    }

    // Install signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    last_object_detection_time = time(NULL);

    // Main loop
    while (running) {
        int object_detected = 0;
        for (int i = 0; i < num_sensors; i++) {
            if (read_distance(&sensors[i]) == 0 && sensors[i].valid_reading) {
                if (sensors[i].distance < DISTANCE_THRESHOLD) {
                    object_detected = 1;
                    last_object_detection_time = time(NULL);
                    log_event("Sensor Triggered", &sensors[i]);
                }
            }
        }

        if (object_detected) {
            if (control_gate(GATE_OPEN)) {
                printf("Gate opened due to object detection\n");
            }
        } else {
            time_t current_time = time(NULL);
            if (difftime(current_time, last_object_detection_time) >= NO_OBJECT_TIMEOUT) {
                if (control_gate(GATE_CLOSED)) {
                    printf("Gate closed due to no object detected for %d seconds\n", NO_OBJECT_TIMEOUT);
                }
            }
