        gpioDelay(100); // Delay for 100ms
    }

    // Cleanup
    printf("Cleaning up...\n");
    i2cClose(i2c_bus_handle);
    gpioWrite(GATE_CONTROL_PIN, GATE_CLOSED); // Ensure gate is closed on exit
    gpioTerminate();
    fclose(log_file);
    free(sensors);

    return 0;
}

