// Define I2C address and GPIO pins
#define VL53L1X_ADDR 0x29
#define GATE_OPEN_PIN 17 // Example GPIO pin for opening the gate
#define GATE_CLOSE_PIN 18 // Example GPIO pin for closing the gate

// Define distance threshold (in mm)
#define DISTANCE_THRESHOLD 500 // 50cm

// Define timeout for no object detection (in seconds)
#define NO_OBJECT_TIMEOUT 3

// Function prototypes
int init_vl53l1x(int i2c_handle);
int read_distance(int i2c_handle, uint16_t *distance);
void open_gate();
void close_gate();
void log_event(const char *event);

// Global variables
bool gate_open = false;
time_t last_object_detection_time;

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pins as output
    gpioSetMode(GATE_OPEN_PIN, PI_OUTPUT);
    gpioSetMode(GATE_CLOSE_PIN, PI_OUTPUT);

    // Open I2C bus
    int i2c_handle = i2cOpen(1, VL53L1X_ADDR, 0); // Bus 1, address 0x29, no flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C bus: %s\n", strerror(errno));
        gpioTerminate();
        return 1;
    }

    // Initialize VL53L1X sensor
    if (init_vl53l1x(i2c_handle) != 0) {
        fprintf(stderr, "VL53L1X initialisation failed\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    printf("VL53L1X sensor initialised successfully\n");

    uint16_t distance;
    time(&last_object_detection_time);

    // Main loop
    while (1) {
        // Read distance from VL53L1X sensor
        if (read_distance(i2c_handle, &distance) == 0) {
            printf("Distance: %d mm\n", distance);

            // Check if object is within the threshold
            if (distance <= DISTANCE_THRESHOLD) {
                time(&last_object_detection_time);
                if (!gate_open) {
                    open_gate();
                }
            } else {
                // Check if timeout has occurred
                time_t current_time;
                time(&current_time);
                if (difftime(current_time, last_object_detection_time) >= NO_OBJECT_TIMEOUT) {
                    if (gate_open) {
                        close_gate();
                    }
                }
            }
        } else {
            fprintf(stderr, "Failed to read distance\n");
        }

        gpioDelay(100); // Delay 100ms
    }

    // Close I2C bus and terminate pigpio (this part will probably never be reached)
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

int init_vl53l1x(int i2c_handle) {
    VL53L1_Error status = VL53L1_ERROR_NONE;
    VL53L1_DevData_t *pMyDevice = (VL53L1_DevData_t*)malloc(sizeof(VL53L1_DevData_t));
    pMyDevice->I2cHandle = i2c_handle;
    pMyDevice->I2cDevAddr = VL53L1X_ADDR;

    status = VL53L1_WaitDeviceBooted(pMyDevice);
    if(status != VL53L1_ERROR_NONE) { fprintf(stderr, "VL53L1_WaitDeviceBooted fail %d\n", status); return -1; }

    status = VL53L1_DataInit(pMyDevice);
    if(status != VL53L1_ERROR_NONE) { fprintf(stderr, "VL53L1_DataInit fail %d\n", status); return -1; }

    status = VL53L1_StaticInit(pMyDevice);
    if(status != VL53L1_ERROR_NONE) { fprintf(stderr, "VL53L1_StaticInit fail %d\n", status); return -1; }

    status = VL53L1_SetPresetMode(pMyDevice, VL53L1_PRESETMODE_AUTONOMOUS);
    if(status != VL53L1_ERROR_NONE) { fprintf(stderr, "VL53L1_SetPresetMode fail %d\n", status); return -1; }

    status = VL53L1_SetDistanceMode(pMyDevice, VL53L1_DISTANCEMODE_MEDIUM);
    if(status != VL53L1_ERROR_NONE) { fprintf(stderr, "VL53L1_SetDistanceMode fail %d\n", status); return -1; }

    status = VL53L1_SetMeasurementTimingBudgetMicroSeconds(pMyDevice, 50000); //50ms
    if(status != VL53L1_ERROR_NONE) { fprintf(stderr, "VL53L1_SetMeasurementTimingBudgetMicroSeconds fail %d\n", status); return -1; }

    status = VL53L1_StartMeasurement(pMyDevice);
    if(status != VL53L1_ERROR_NONE) { fprintf(stderr, "VL53L1_StartMeasurement fail %d\n", status); return -1; }

    return 0;
}

int read_distance(int i2c_handle, uint16_t *distance) {
    VL53L1_Error status = VL53L1_ERROR_NONE;
    VL53L1_DevData_t *pMyDevice = (VL53L1_DevData_t*)malloc(sizeof(VL53L1_DevData_t));
    pMyDevice->I2cHandle = i2c_handle;
    pMyDevice->I2cDevAddr = VL53L1X_ADDR;
    VL53L1_RangingMeasurementData_t RangingData;

    status = VL53L1_WaitMeasurementDataReady(pMyDevice);
    if(status != VL53L1_ERROR_NONE) { fprintf(stderr, "VL53L1_WaitMeasurementDataReady fail %d\n", status); return -1; }

    status = VL53L1_GetRangingMeasurementData(pMyDevice, &RangingData);
    if(status != VL53L1_ERROR_NONE) { fprintf(stderr, "VL53L1_GetRangingMeasurementData fail %d\n", status); return -1; }

    status = VL53L1_ClearInterruptAndStartMeasurement(pMyDevice);
    if(status != VL53L1_ERROR_NONE) { fprintf(stderr, "VL53L1_ClearInterruptAndStartMeasurement fail %d\n", status); return -1; }

    *distance = RangingData.RangeMilliMeter;

    return 0;
}

void open_gate() {
    printf("Opening gate\n");
    gpioWrite(GATE_OPEN_PIN, 1);
    gpioWrite(GATE_CLOSE_PIN, 0);
    gate_open = true;
    log_event("Gate opened");
}

void close_gate() {
    printf("Closing gate\n");
    gpioWrite(GATE_OPEN_PIN, 0);
    gpioWrite(GATE_CLOSE_PIN, 1);
    gate_open = false;
    log_event("Gate closed");
}

void log_event(const char *event) {
    FILE *fp = fopen("gate_log.txt", "a");
    if (fp == NULL) {
        fprintf(stderr, "Failed to open log file\n");
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(fp, "[%d-%02d-%02d %02d:%02d:%02d] %s\n", tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, event);
    fclose(fp);
}

