        fprintf(stderr, "Error: Failed to send initialization command.\n");
        return -1;
    }
    gpioDelay(10); // Wait for initialization to complete
    return 0;
}

// Function to read temperature and humidity from the AHT20 sensor
int aht20_read(int i2c_handle, float *temperature, float *humidity) {
    char measure_cmd[3] = {AHT20_MEASURE, 0x33, 0x00};
    unsigned char data[6];

    if (i2cWriteI2C(i2c_handle, measure_cmd, 3) != 0) {
        fprintf(stderr, "Error: Failed to send measurement command.\n");
        return -1;
    }
    gpioDelay(80); // Wait for measurement to complete

    if (i2cReadI2C(i2c_handle, (char *)data, 6) != 6) {
        fprintf(stderr, "Error: Failed to read data from sensor.\n");
        return -1;
    }

    // Check if the sensor is busy
    if (data[0] & 0x80) {
        fprintf(stderr, "Error: Sensor is busy.\n");
        return -1;
    }

    // Calculate humidity
    unsigned long humidity_raw = ((unsigned long)data[1] << 12) | ((unsigned long)data[2] << 4) | (data[3] >> 4);
    *humidity = (float)humidity_raw * 100.0 / 0x100000;

    // Calculate temperature
    unsigned long temperature_raw = ((unsigned long)(data[3] & 0x0F) << 16) | ((unsigned long)data[4] << 8) | data[5];
    *temperature = (float)temperature_raw * 200.0 / 0x100000 - 50;

    return 0;
}

