    if (aht20_init(i2c_handle) != 0) {
        fprintf(stderr, "Error: AHT20 initialization failed.\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    gpioSetMode(FAN_PIN, PI_OUTPUT); // Set FAN_PIN as output
    gpioWrite(FAN_PIN, 0); // Initially turn the fan off

