#define DOOR_DOWN_PIN 4

// Define relay activation time (seconds)
#define RELAY_ACTIVE_TIME 5

// Define door states
typedef enum {
    OPEN, CLOSED, OPENING, CLOSING, UNKNOWN
} DoorState;

// Structure to hold relay pin information
typedef struct {
    int up_pin;
    int down_pin;
} RelayPins;

// Global variables
FILE *log_file = NULL;
volatile sig_atomic_t keep_running = 1;

// Function prototypes
void open_door(void *context);
void close_door(void *context);
DoorState get_door_status(const RelayPins *pins);
void log_door_status(const char *action);
void signal_handler(int sig);

// Function pointer type for door control
typedef void (*DoorControlFunc)(void *context);

// Signal handler for graceful shutdown
void signal_handler(int sig) {
    syslog(LOG_INFO, "Signal received, shutting down...");
    keep_running = 0;
}

// Function to open the chicken coop door
void open_door(void *context) {
    RelayPins *pins = (RelayPins *)context;
    time_t now;
    time(&now);
    struct tm *timeinfo = localtime(&now);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    // Safety interlock: Ensure only one relay is active at a time
    digitalWrite(pins->down_pin, LOW);
    delay(100); // Small delay to ensure relay deactivation

    digitalWrite(pins->up_pin, HIGH);
    log_door_status("OPENING");
    syslog(LOG_INFO, "%s [OPENING] Door via [wiringPi]", timestamp);
    delay(RELAY_ACTIVE_TIME * 1000); // Activate relay for specified time
    digitalWrite(pins->up_pin, LOW);
    log_door_status("OPENED");
    syslog(LOG_INFO, "%s [OPENED] Door via [wiringPi]", timestamp);
}

// Function to close the chicken coop door
void close_door(void *context) {
    RelayPins *pins = (RelayPins *)context;
    time_t now;
    time(&now);
    struct tm *timeinfo = localtime(&now);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    // Safety interlock: Ensure only one relay is active at a time
    digitalWrite(pins->up_pin, LOW);
    delay(100); // Small delay to ensure relay deactivation

    digitalWrite(pins->down_pin, HIGH);
    log_door_status("CLOSING");
    syslog(LOG_INFO, "%s [CLOSING] Door via [wiringPi]", timestamp);
    delay(RELAY_ACTIVE_TIME * 1000); // Activate relay for specified time
    digitalWrite(pins->down_pin, LOW);
    log_door_status("CLOSED");
    syslog(LOG_INFO, "%s [CLOSED] Door via [wiringPi]", timestamp);
}

// Function to get the current door status
DoorState get_door_status(const RelayPins *pins) {
    int up_state = digitalRead(pins->up_pin);
    int down_state = digitalRead(pins->down_pin);

    if (up_state == HIGH && down_state == LOW) {
        return OPENING;
    } else if (up_state == LOW && down_state == HIGH) {
        return CLOSING;
    } else if (up_state == LOW && down_state == LOW) {
        return CLOSED; // Assuming both low means closed
    } else {
        return UNKNOWN;
    }
}

// Function to log door status to file
void log_door_status(const char *action) {
    if (log_file != NULL) {
        time_t now;
        time(&now);
        struct tm *timeinfo = localtime(&now);
        char timestamp[20];
        strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);
        fprintf(log_file, "%s [%s] Door via [wiringPi]\n", timestamp, action);
        fflush(log_file); // Ensure data is written to disk
    } else {
        syslog(LOG_ERR, "Log file not open.");
        perror("Log file not open");
    }
}

int main(void) {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        syslog(LOG_ERR, "wiringPiSetup failed: %s", strerror(errno));
        return 1;
    }

    // Initialize syslog
    openlog("chicken_door", LOG_PID | LOG_CONS, LOG_USER);

    // Set GPIO pins as output
    pinMode(DOOR_UP_PIN, OUTPUT);
    pinMode(DOOR_DOWN_PIN, OUTPUT);

    // Initialize relay pins structure
    RelayPins pins = {DOOR_UP_PIN, DOOR_DOWN_PIN};

    // Initialize log file
    log_file = fopen("door_log.txt", "a");
    if (log_file == NULL) {
        perror("Error opening log file");
        syslog(LOG_ERR, "Error opening log file: %s", strerror(errno));
        closelog(); // Close syslog before exiting
        return 1;
    }

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Main loop
    while (keep_running) {
        time_t now;
        time(&now);
        struct tm *timeinfo = localtime(&now);

        // Simulate open at 7 AM and close at 7 PM
        if (timeinfo->tm_hour == 7 && timeinfo->tm_min == 0 && timeinfo->tm_sec == 0) {
            open_door(&pins);
        } else if (timeinfo->tm_hour == 19 && timeinfo->tm_min == 0 && timeinfo->tm_sec == 0) {
            close_door(&pins);
        }

        // Log door status periodically (e.g., every hour)
        if (timeinfo->tm_min == 0 && timeinfo->tm_sec == 0) {
            DoorState current_state = get_door_status(&pins);
            char state_string[20];
            switch (current_state) {
                case OPEN:
                    snprintf(state_string, sizeof(state_string), "OPEN");
                    break;
                case CLOSED:
                    snprintf(state_string, sizeof(state_string), "CLOSED");
                    break;
                case OPENING:
                    snprintf(state_string, sizeof(state_string), "OPENING");
                    break;
                case CLOSING:
                    snprintf(state_string, sizeof(state_string), "CLOSING");
                    break;
                default:
                    snprintf(state_string, sizeof(state_string), "UNKNOWN");
                    break;
            }
            syslog(LOG_INFO, "Door status: %s", state_string);
        }

        delay(10000); // Check every 10 seconds
    }

    // Cleanup resources before exiting
    syslog(LOG_INFO, "Closing door...");
    close_door(&pins); // Ensure door is closed on exit

    syslog(LOG_INFO, "Closing log file...");
    if (log_file != NULL) {
        fclose(log_file);
    }

