void reload_configuration(int sig);

// Function implementations

// Reload configuration
void reload_configuration(int sig) {
    if (sig == SIGHUP) {
        syslog(LOG_INFO, "Received SIGHUP. Reloading configuration...");
        if (read_config_from_file(CONFIG_FILE) != 0) {
            syslog(LOG_ERR, "Failed to reload configuration.");
        } else {
            syslog(LOG_INFO, "Configuration reloaded successfully.");
        }
    }
}

// Signal handler for graceful shutdown
void signal_handler(int sig) {
    syslog(LOG_INFO, "Signal received, shutting down...");
    running = 0;

    // Cleanup resources
    pthread_mutex_destroy(&sensor_data_mutex);

    if (mosq) {
        mosquitto_disconnect(mosq);
        mosquitto_destroy(mosq);
        mosquitto_lib_cleanup();
    }

    closelog();
    exit(0);
}

// Watchdog timer handler
void watchdog_handler(int sig) {
    if (sig == SIGABRT) {
        syslog(LOG_ERR, "Watchdog timer expired. Restarting...");
        // Perform any necessary cleanup before restarting
        closelog();
        raise(SIGKILL); // Forcefully terminate the process to trigger a restart
    }
}

// Setup watchdog timer
void setup_watchdog_timer() {
    struct sigevent sev;
    struct itimerspec its;

    memset(&sev, 0, sizeof(sev));
    sev.sigev_notify = SIGEV_SIGNAL;
    sev.sigev_signo = SIGABRT;

    if (timer_create(CLOCK_REALTIME, &sev, &watchdog_timer) == -1) {
        syslog(LOG_ERR, "Failed to create watchdog timer: %s", strerror(errno));
        perror("timer_create");
        exit(EXIT_FAILURE);
    }

    its.it_value.tv_sec = WATCHDOG_INTERVAL;
    its.it_value.tv_nsec = 0;
    its.it_interval.tv_sec = WATCHDOG_INTERVAL;
    its.it_interval.tv_nsec = 0;

    if (timer_settime(watchdog_timer, 0, &its, NULL) == -1) {
        syslog(LOG_ERR, "Failed to set watchdog timer: %s", strerror(errno));
        perror("timer_settime");
        exit(EXIT_FAILURE);
    }

    syslog(LOG_INFO, "Watchdog timer started with interval %d seconds.", WATCHDOG_INTERVAL);
}

// Reset watchdog timer
void reset_watchdog_timer() {
    struct itimerspec its;

    its.it_value.tv_sec = WATCHDOG_INTERVAL;
    its.it_value.tv_nsec = 0;
    its.it_interval.tv_sec = WATCHDOG_INTERVAL;
    its.it_interval.tv_nsec = 0;

    if (timer_settime(watchdog_timer, 0, &its, NULL) == -1) {
        syslog(LOG_ERR, "Failed to reset watchdog timer: %s", strerror(errno));
        perror("timer_settime");
    }

    //syslog(LOG_DEBUG, "Watchdog timer reset.");
}

// Read configuration from JSON file
int read_config_from_file(const char *filename) {
    json_t *root;
    json_error_t error;

    root = json_load_file(filename, 0, &error);
    if (!root) {
        syslog(LOG_ERR, "Error loading JSON file: %s at line %d, column %d", error.text, error.line, error.column);
        return -1;
    }

    json_t *temp_high = json_object_get(root, "temp_high_threshold");
    json_t *temp_low = json_object_get(root, "temp_low_threshold");
    json_t *humidity_high = json_object_get(root, "humidity_high_threshold");
    json_t *humidity_low = json_object_get(root, "humidity_low_threshold");
    json_t *mqtt_broker = json_object_get(root, "mqtt_broker_address");
    json_t *mqtt_port = json_object_get(root, "mqtt_broker_port");
    json_t *mqtt_id = json_object_get(root, "mqtt_client_id");
    json_t *mqtt_user = json_object_get(root, "mqtt_username");
    json_t *mqtt_pass = json_object_get(root, "mqtt_password");

    if (temp_high && json_is_real(temp_high)) temp_high_threshold = json_real_value(temp_high);
    if (temp_low && json_is_real(temp_low)) temp_low_threshold = json_real_value(temp_low);
    if (humidity_high && json_is_real(humidity_high)) humidity_high_threshold = json_real_value(humidity_high);
    if (humidity_low && json_is_real(humidity_low)) humidity_low_threshold = json_real_value(humidity_low);
    if (mqtt_broker && json_is_string(mqtt_broker)) {
        free(mqtt_broker_address);
        mqtt_broker_address = strdup(json_string_value(mqtt_broker));
    }
    if (mqtt_port && json_is_integer(mqtt_port)) mqtt_broker_port = json_integer_value(mqtt_port);
    if (mqtt_id && json_is_string(mqtt_id)) {
        free(mqtt_client_id);
        mqtt_client_id = strdup(json_string_value(mqtt_id));
    }
    if (mqtt_user && json_is_string(mqtt_user)) {
        free(mqtt_username);
        mqtt_username = strdup(json_string_value(mqtt_user));
    }
    if (mqtt_pass && json_is_string(mqtt_pass)) {
        free(mqtt_password);
        mqtt_password = strdup(json_string_value(mqtt_pass));
    }

    json_decref(root);
    syslog(LOG_INFO, "Configuration loaded successfully.");
    return 0;
}

// Read DHT22 sensor data
int read_dht22_sensor(double *temperature, double *humidity) {
    int data[5] = {0, 0, 0, 0, 0};
    int laststate = HIGH;
    int j = 0;

    // Reset data array
    data[0] = data[1] = data[2] = data[3] = data[4] = 0;

    // Request data
    pinMode(DHT_PIN, OUTPUT);
    digitalWrite(DHT_PIN, LOW);
    delay(18);
    digitalWrite(DHT_PIN, HIGH);
    delayMicroseconds(40);
    pinMode(DHT_PIN, INPUT);

    // Get data
    unsigned int loops = 100000;
    for (int i = 0; i < loops; i++) {
        int currentState = digitalRead(DHT_PIN);
        if (currentState != laststate) {
            unsigned int counter = 0;
            while (digitalRead(DHT_PIN) == currentState) {
                counter++;
                delayMicroseconds(1); // Reduced delay for faster loop
                if (counter == 255) {
                    break;
                }
            }

            if (counter >= 255) {
                break;
            }

            if ((i > 4) && (i < 45)) {
                data[j / 8] <<= 1;
                if (counter > 16) {
                    data[j / 8] |= 1;
                }
                j++;
            }
        }
        laststate = currentState;
    }

    // Check we read 40 bits (8bit x 5 )
    if (j < 40) {
        syslog(LOG_ERR, "DHT22: Not enough data received, only %d bits", j);
        return -1;
    }

    // Verify checksum
    if (data[4] != ((data[0] + data[1] + data[2] + data[3]) & 0xFF)) {
        syslog(LOG_ERR, "DHT22: Checksum failure: %d != %d", data[4], ((data[0] + data[1] + data[2] + data[3]) & 0xFF));
        return -1;
    }

    // Get temperature and humidity
    *humidity = (double)((data[0] << 8) + data[1]) / 10.0;
    if (*humidity > 100.0) {
        *humidity = data[0]; // for DHT11
    }
    *temperature = (double)(((data[2] & 0x7F) << 8) + data[3]) / 10.0;
    if (data[2] & 0x80) {
        *temperature = -*temperature;
    }

    return 0;
}

// Validate temperature reading
int validate_temperature(double temperature) {
    if (temperature < -40.0 || temperature > 80.0) {
        syslog(LOG_ERR, "Invalid temperature reading: %.2f", temperature);
        return -1;
    }
    return 0;
}

// Validate humidity reading
int validate_humidity(double humidity) {
    if (humidity < 0.0 || humidity > 100.0) {
        syslog(LOG_ERR, "Invalid humidity reading: %.2f", humidity);
        return -1;
    }
    return 0;
}

// Check if temperature exceeds threshold
int check_temp_high_threshold(double temperature, double threshold_high, double threshold_low) {
    return (temperature > threshold_high || temperature < threshold_low);
}

// Check if humidity exceeds threshold
int check_humidity_high_threshold(double humidity, double threshold_high, double threshold_low) {
    return (humidity > threshold_high || humidity < threshold_low);
}

// Log sensor data
int log_sensor_data(double temperature, double humidity) {
    time_t now = time(NULL);
    struct tm tstruct;
    char buf[80];
    localtime_r(&now, &tstruct);
    strftime(buf, sizeof(buf), "%Y-%m-%d.%X", &tstruct);

    syslog(LOG_INFO, "Timestamp: %s, Temperature: %.2f, Humidity: %.2f", buf, temperature, humidity);
    return 0;
}

// Publish data to MQTT broker
int mqtt_publish_data(double temperature, double humidity) {
    int rc;
    char *payload = NULL;
    json_t *root = json_object();
    json_t *timestamp = json_integer((json_int_t)time(NULL));
    json_t *temp = json_real(temperature);
    json_t *humid = json_real(humidity);
    json_t *temp_exceeded = json_boolean(check_temp_high_threshold(temperature, temp_high_threshold, temp_low_threshold));
    json_t *humid_exceeded = json_boolean(check_humidity_high_threshold(humidity, humidity_high_threshold, humidity_low_threshold));

    json_object_set_new(root, "timestamp", timestamp);
    json_object_set_new(root, "temperature", temp);
    json_object_set_new(root, "humidity", humid);
    json_object_set_new(root, "temp_exceeded", temp_exceeded);
    json_object_set_new(root, "humid_exceeded", humid_exceeded);

    payload = json_dumps(root, JSON_REAL_PRECISION(10));
    json_decref(root);

    if (!payload) {
        syslog(LOG_ERR, "Failed to create JSON payload.");
        return -1;
    }

    rc = mosquitto_publish(mosq, NULL, MQTT_TOPIC, strlen(payload), payload, 1, false);
    free(payload);

    if (rc != MOSQ_ERR_SUCCESS) {
        syslog(LOG_ERR, "MQTT publish error: %s", mosquitto_strerror(rc));
        return -1;
    }

    return 0;
}

// Sensor reading thread
void *sensor_reading_thread(void *arg) {
    (void)arg; // Suppress unused parameter warning
    SensorReadFunc read_sensor = read_dht22_sensor;
    DataValidateFunc validate_temp = validate_temperature;
    DataValidateFunc validate_humidity = validate_humidity;
    ThresholdCompareFunc check_temp = check_temp_high_threshold;
    ThresholdCompareFunc check_humidity = check_humidity_high_threshold;
    DataLogFunc log_data = log_sensor_data;

    while (running) {
        reset_watchdog_timer();

        double current_temperature, current_humidity;
        int retry_count = 0;
        int max_retries = 5;

        while (retry_count < max_retries) {
            if (read_sensor(&current_temperature, &current_humidity) == 0) {
                if (validate_temp(current_temperature, current_humidity) == 0 && validate_humidity(current_temperature, current_humidity) == 0) {
                    pthread_mutex_lock(&sensor_data_mutex);
                    temperature = current_temperature;
                    humidity = current_humidity;
                    pthread_mutex_unlock(&sensor_data_mutex);
                    break; // Exit retry loop on successful read
                } else {
                    syslog(LOG_ERR, "Sensor data validation failed. Retrying...");
                }
            } else {
                syslog(LOG_ERR, "Sensor read error. Retrying...");
            }

            retry_count++;
            sleep(retry_count * 2); // Exponential backoff
        }

        if (retry_count == max_retries) {
            syslog(LOG_ERR, "Max sensor read retries reached. Skipping data logging and MQTT publishing.");
            sleep(10); // Prevent flooding the log with errors
            continue; // Skip to the next iteration of the loop
        }

        if (check_temp(temperature, temp_high_threshold, temp_low_threshold) || check_humidity(humidity, humidity_high_threshold, humidity_low_threshold)) {
            log_data(temperature, humidity);
        }

        sleep(5); // Delay between sensor readings
    }

    pthread_exit(NULL);
}

// MQTT publishing thread
void *mqtt_publishing_thread(void *arg) {
    (void)arg; // Suppress unused parameter warning
    ThresholdCompareFunc check_temp = check_temp_high_threshold;
    ThresholdCompareFunc check_humidity = check_humidity_high_threshold;

    while (running) {
        reset_watchdog_timer();

        pthread_mutex_lock(&sensor_data_mutex);
        double temp_to_publish = temperature;
        double humidity_to_publish = humidity;
        pthread_mutex_unlock(&sensor_data_mutex);

        if (check_temp(temp_to_publish, temp_high_threshold, temp_low_threshold) || check_humidity(humidity_to_publish, humidity_high_threshold, humidity_low_threshold)) {
            if (mqtt_publish_data(temp_to_publish, humidity_to_publish) != 0) {
                syslog(LOG_ERR, "Failed to publish data to MQTT broker.");
            }
        }

        sleep(10); // Delay between MQTT publishes
    }

    pthread_exit(NULL);
}

int main() {
    // Initialize syslog
    openlog("sensor_monitor", LOG_PID | LOG_CONS, LOG_USER);

    // Install signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);
    signal(SIGHUP, reload_configuration);
    signal(SIGABRT, watchdog_handler);

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        syslog(LOG_ERR, "wiringPiSetup failed, exiting.");
        return 1;
    }

    // Read configuration from file
    if (read_config_from_file(CONFIG_FILE) != 0) {
        syslog(LOG_ERR, "Failed to read configuration, exiting.");
        return 1;
    }

    // Initialize MQTT client
    mosquitto_lib_init();
    mosq = mosquitto_new(mqtt_client_id, true, NULL);
    if (!mosq) {
        syslog(LOG_ERR, "Failed to create MQTT client.");
        return 1;
    }

    if (mqtt_username && mqtt_password) {
        mosquitto_username_pw_set(mosq, mqtt_username, mqtt_password);
    }

    // Configure TLS
    // mosquitto_tls_set(mosq, NULL, NULL, "/etc/ssl/certs/ca-certificates.crt", NULL, NULL);
    // mosquitto_tls_opts_set(mosq, 1, "tlsv1.2", NULL);

    int rc = mosquitto_connect(mosq, mqtt_broker_address, mqtt_broker_port, 60);
    if (rc != MOSQ_ERR_SUCCESS) {
        syslog(LOG_ERR, "MQTT connect error: %s", mosquitto_strerror(rc));
        mosquitto_destroy(mosq);
        mosquitto_lib_cleanup();
        return 1;
    }

    mosquitto_loop_start(mosq);

    // Setup watchdog timer
    setup_watchdog_timer();

    // Create threads
    pthread_t sensor_thread, mqtt_thread;
    if (pthread_create(&sensor_thread, NULL, sensor_reading_thread, NULL) != 0) {
        syslog(LOG_ERR, "Failed to create sensor reading thread.");
        return 1;
    }
    if (pthread_create(&mqtt_thread, NULL, mqtt_publishing_thread, NULL) != 0) {
        syslog(LOG_ERR, "Failed to create MQTT publishing thread.");
        return 1;
    }

    // Wait for threads to finish (never happens in this example)
    pthread_join(sensor_thread, NULL);
    pthread_join(mqtt_thread, NULL);

    // Cleanup resources (should be reached only on signal)
    mosquitto_disconnect(mosq);
    mosquitto_destroy(mosq);
    mosquitto_lib_cleanup();

    closelog();
    return 0;
}

