#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <wiringPi.h>
#include <dht22.h>
#include <jansson.h>
#include <time.h>

#define DHT22_PIN 4
#define CONFIG_FILE "file_logging.json"
#define LOG_FILE "sensor_log.txt"

// Structure to hold threshold values
typedef struct {
    float temperature_max;
    float temperature_min;
    float humidity_max;
    float humidity_min;
} Thresholds;

// Function to read thresholds from JSON file
int read_thresholds(const char *filename, Thresholds *thresholds) {
    json_t *root, *temperature, *humidity;
    json_error_t error;

    root = json_load_file(filename, 0, &error);
    if (!root) {
        fprintf(stderr, "Error: Could not load JSON from file: %s. %s\n", filename, error.text);
        return 1;
    }

    temperature = json_object_get(root, "temperature");
    humidity = json_object_get(root, "humidity");

    if (!json_is_object(temperature) || !json_is_object(humidity)) {
        fprintf(stderr, "Error: Invalid JSON structure.  'temperature' or 'humidity' not found or not an object.\n");
        json_decref(root);
        return 1;
    }

    if (json_unpack(temperature, "{s:f, s:f}", "max", &thresholds->temperature_max, "min", &thresholds->temperature_min) != 0) {
        fprintf(stderr, "Error: Could not extract temperature thresholds.\n");
        json_decref(root);
        return 1;
    }

    if (json_unpack(humidity, "{s:f, s:f}", "max", &thresholds->humidity_max, "min", &thresholds->humidity_min) != 0) {
        fprintf(stderr, "Error: Could not extract humidity thresholds.\n");
        json_decref(root);
        return 1;
    }

    json_decref(root);
    return 0;
}

// Function to log data to file
void log_data(float temperature, float humidity) {
    FILE *fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(fp, "%d-%02d-%02d %02d:%02d:%02d, Temperature: %.2f, Humidity: %.2f\n", tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, temperature, humidity);
    fclose(fp);
}

int main() {
    Thresholds thresholds;
    float temperature, humidity;
    int result;

    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error: Unable to initialize wiringPi.\n");
        return 1;
    }

    if (read_thresholds(CONFIG_FILE, &thresholds) != 0) {
        fprintf(stderr, "Error: Failed to read thresholds from %s.  Using default values of max temp 30, min temp 10, max humidity 80, min humidity 20.\n", CONFIG_FILE);
        thresholds.temperature_max = 30.0;
        thresholds.temperature_min = 10.0;
        thresholds.humidity_max = 80.0;
        thresholds.humidity_min = 20.0;
    }

    printf("Monitoring DHT22 sensor on GPIO %d. Logging to %s.\n", DHT22_PIN, LOG_FILE);
    printf("Temperature thresholds: min=%.2f, max=%.2f\n", thresholds.temperature_min, thresholds.temperature_max);
    printf("Humidity thresholds: min=%.2f, max=%.2f\n", thresholds.humidity_min, thresholds.humidity_max);

    while (1) {
        result = dht22Read(DHT22_PIN);

        if (result == DHT_OK) {
            temperature = dht22Temperature();
            humidity = dht22Humidity();

            if (temperature > thresholds.temperature_max || temperature < thresholds.temperature_min ||
                humidity > thresholds.humidity_max || humidity < thresholds.humidity_min) {
                log_data(temperature, humidity);
                printf("Logged: Temperature: %.2f, Humidity: %.2f\n", temperature, humidity);
            }
        } else {
            fprintf(stderr, "Error reading DHT22 sensor: %d\n", result);
        }

        delay(2000); // Wait 2 seconds
    }

    return 0;
}

