// Function to read temperature and humidity from the SHT31-DIS
int readTemperatureAndHumidity(int fd, float *temperature, float *humidity) {
    // Send measurement command
    if (wiringPiI2CWrite(fd, (MEAS_HIGHREP >> 8)) == -1) {
        fprintf(stderr, "Error writing MSB of command: %s\n", strerror(errno));
        return -1;
    }
    if (wiringPiI2CWrite(fd, (MEAS_HIGHREP & 0xFF)) == -1) {
        fprintf(stderr, "Error writing LSB of command: %s\n", strerror(errno));
        return -1;
    }

    // Wait for measurement to complete (typical conversion time is 15ms for high repeatability)
    delay(20); 

    // Read 6 bytes of data (Temp MSB, Temp LSB, Temp CRC, Humid MSB, Humid LSB, Humid CRC)
    uint8_t data[6];
    for (int i = 0; i < 6; i++) {
        int result = wiringPiI2CRead(fd);
        if (result == -1) {
            fprintf(stderr, "Error reading byte %d: %s\n", i, strerror(errno));
            return -1;
        }
        data[i] = (uint8_t)result;
    }

    // Convert the data
    int temp_raw = (data[0] << 8) | data[1];
    int humid_raw = (data[3] << 8) | data[4];

    // Perform CRC check (not implemented in this example for brevity)
    // In a real application, you should implement CRC check for data integrity

    // Convert raw data to temperature and humidity (Celsius and %RH)
    *temperature = -45.0 + (175.0 * (float)temp_raw / 65535.0);
    *humidity = 100.0 * (float)humid_raw / 65535.0;

    return 0;
}

