        fprintf(stderr, "VL53L1X_SetUserSequenceConfig failed: %d\n", status);
        return -1;
    }

    status = VL53L1X_SetTuningParameter(Dev, 1, 12);
    if (status != VL53L1X_ERROR_NONE) {
        fprintf(stderr, "VL53L1X_SetTuningParameter failed: %d\n", status);
        return -1;
