    if (wiringPiISR(PIR_PIN, INT_EDGE_RISING, motionDetected) < 0) {
        fprintf(stderr, "Error setting up ISR!\n");
        return 1;
    }

    printf("PIR sensor and LED control started. Press Ctrl+C to exit.\n");

