}

// Function to read pressure from BMP180 sensor
int read_bmp180(int i2c_handle, float *pressure, bmp180_calibration_data cal_data) {
    char buf[3];
    int ut, up;
    long x1, x2, x3, b3, b5, b6, p;
    unsigned long b4, b7;

    // Request temperature reading
    if (i2cWriteByteData(i2c_handle, BMP180_REG_CONTROL, 0x2E) != 0) {
        fprintf(stderr, "Error writing to control register (temp)\n");
        return -1;
    }
    time_sleep(0.005); // Wait 4.5ms

    // Read uncompensated temperature (UT)
    if (i2cReadI2CBlockData(i2c_handle, BMP180_REG_MSB, buf, 2) != 2) {
        fprintf(stderr, "Error reading temperature data\n");
        return -1;
    }
    ut = (buf[0] << 8) + buf[1];

    // Request pressure reading
    if (i2cWriteByteData(i2c_handle, BMP180_REG_CONTROL, 0x34 + (OSS << 6)) != 0) {
        fprintf(stderr, "Error writing to control register (pressure)\n");
        return -1;
    }
    time_sleep(0.008); // Wait 7.5ms (OSS = 0)

    // Read uncompensated pressure (UP)
    if (i2cReadI2CBlockData(i2c_handle, BMP180_REG_MSB, buf, 3) != 3) {
        fprintf(stderr, "Error reading pressure data\n");
        return -1;
    }
    up = ((unsigned long) buf[0] << 16 | (unsigned long) buf[1] << 8 | (unsigned long) buf[2]) >> (8 - OSS);


    // Calculate temperature
    x1 = ((long)ut - (long)cal_data.AC6) * ((long)cal_data.AC5) / pow(2, 15);
    x2 = ((long)cal_data.MC * pow(2, 11)) / (x1 + (long)cal_data.MD);
