#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>

// Configuration
#define CONFIG_FILE "config.txt"
#define BUZZER_PIN 27

// Sensor Definitions
#define SENSOR1_TRIGGER 17
#define SENSOR1_ECHO 18
#define SENSOR2_TRIGGER 22
#define SENSOR2_ECHO 23
#define SENSOR3_TRIGGER 24
#define SENSOR3_ECHO 25

#define NUM_SENSORS 3

// Proximity Zones (in cm)
#define ZONE1_THRESHOLD 20
#define ZONE2_THRESHOLD 50

// Error Codes
#define SUCCESS 0
#define ERROR_TIMEOUT -1
#define ERROR_INVALID_READING -2
#define ERROR_GPIO_INIT -3
#define ERROR_CONFIG -4

// Data Structures
typedef struct {
    int frequency;
    int duration;
} Note;

typedef enum {
    ZONE_CLOSE,
    ZONE_MEDIUM,
    ZONE_FAR
} ProximityZone;

typedef struct {
    int trigger_pin;
    int echo_pin;
    ProximityZone zone;
    float distance;
} SensorData;

// Global Variables (try to minimize)
static volatile int terminate = 0;
static int volume = 128; // Default volume

// Function Prototypes
int init_gpio();
int read_config();
int read_distance(int trigger_pin, int echo_pin, float *distance);
ProximityZone determine_proximity_zone(float distance);
void play_melody(const Note *melody, int melody_length, int volume);
void signal_handler(int signal);
void stop_buzzer();

// Melodies (Example)
Note melody_close[] = {{440, 200}, {494, 200}, {523, 200}}; // A4, B4, C5
Note melody_medium[] = {{392, 300}, {440, 300}};          // G4, A4
Note melody_far[] = {{262, 400}, {294, 400}};             // C4, D4

// Melody Mapping (Sensor -> Zone -> Melody)
const Note *get_melody(int sensor_id, ProximityZone zone)
{
    switch (sensor_id) {
        case 1:
            switch (zone) {
                case ZONE_CLOSE: return melody_close;
                case ZONE_MEDIUM: return melody_medium;
                case ZONE_FAR: return melody_far;
            }
            break;
        case 2:
            switch (zone) {
                case ZONE_CLOSE: return melody_medium;
                case ZONE_MEDIUM: return melody_far;
                case ZONE_FAR: return melody_close;
            }
            break;
        case 3:
            switch (zone) {
                case ZONE_CLOSE: return melody_far;
                case ZONE_MEDIUM: return melody_close;
                case ZONE_FAR: return melody_medium;
            }
            break;
    }
    return NULL; // Default: no melody
}

int get_melody_length(int sensor_id, ProximityZone zone)
{
    switch (sensor_id) {
        case 1:
            switch (zone) {
                case ZONE_CLOSE: return sizeof(melody_close) / sizeof(melody_close[0]);
                case ZONE_MEDIUM: return sizeof(melody_medium) / sizeof(melody_medium[0]);
                case ZONE_FAR: return sizeof(melody_far) / sizeof(melody_far[0]);
            }
            break;
        case 2:
            switch (zone) {
                case ZONE_CLOSE: return sizeof(melody_medium) / sizeof(melody_medium[0]);
                case ZONE_MEDIUM: return sizeof(melody_far) / sizeof(melody_far[0]);
                case ZONE_FAR: return sizeof(melody_close) / sizeof(melody_close[0]);
            }
            break;
        case 3:
            switch (zone) {
                case ZONE_CLOSE: return sizeof(melody_far) / sizeof(melody_far[0]);
                case ZONE_MEDIUM: return sizeof(melody_close) / sizeof(melody_close[0]);
                case ZONE_FAR: return sizeof(melody_medium) / sizeof(melody_medium[0]);
            }
            break;
    }
    return 0; // Default: no melody
}


int main(int argc, char *argv[]) {
    SensorData sensors[NUM_SENSORS];
    sensors[0].trigger_pin = SENSOR1_TRIGGER;
    sensors[0].echo_pin = SENSOR1_ECHO;
    sensors[1].trigger_pin = SENSOR2_TRIGGER;
    sensors[1].echo_pin = SENSOR2_ECHO;
    sensors[2].trigger_pin = SENSOR3_TRIGGER;
    sensors[2].echo_pin = SENSOR3_ECHO;

    if (argc > 1) {
        volume = atoi(argv[1]);
        if (volume < 0) volume = 0;
        if (volume > 255) volume = 255;
    }

    if (init_gpio() != SUCCESS) {
        fprintf(stderr, "Error initializing GPIO. Exiting.\n");
        return 1;
    }

    if (read_config() != SUCCESS) {
        fprintf(stderr, "Warning: Could not read config file. Using default settings.\n");
    }

    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    printf("Proximity Alert System started. Press Ctrl+C to exit.\n");

    while (!terminate) {
        int highest_priority_sensor = -1;
        ProximityZone highest_priority_zone;

        for (int i = 0; i < NUM_SENSORS; i++) {
            float distance;
            int result = read_distance(sensors[i].trigger_pin, sensors[i].echo_pin, &distance);
            if (result == SUCCESS) {
                sensors[i].distance = distance;
                sensors[i].zone = determine_proximity_zone(distance);

                // Simple priority logic: lower sensor ID = higher priority
                if (sensors[i].zone != ZONE_FAR) {
                    if (highest_priority_sensor == -1 || i < highest_priority_sensor) {
                        highest_priority_sensor = i;
                        highest_priority_zone = sensors[i].zone;
                    }
                }
            } else {
                fprintf(stderr, "Error reading sensor %d: %d\n", i + 1, result);
            }
        }

        if (highest_priority_sensor != -1) {
            const Note *melody = get_melody(highest_priority_sensor + 1, sensors[highest_priority_sensor].zone);
            int melody_length = get_melody_length(highest_priority_sensor + 1, sensors[highest_priority_sensor].zone);
            if (melody != NULL) {
                play_melody(melody, melody_length, volume);
            }
            // Add a small delay to avoid playing the same melody repeatedly
            gpioDelay(500); // 500ms delay
        } else {
            // No sensors triggered, ensure the buzzer is off
            stop_buzzer();
        }

        gpioDelay(100); // Check sensors every 100ms
    }

    stop_buzzer();
    gpioTerminate();
    printf("Exiting cleanly.\n");
    return 0;
}

int init_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return ERROR_GPIO_INIT;
    }

    gpioSetMode(BUZZER_PIN, PI_OUTPUT);
    gpioSetPWMfrequency(BUZZER_PIN, 2000); // Set PWM frequency for buzzer

    gpioSetMode(SENSOR1_TRIGGER, PI_OUTPUT);
    gpioSetMode(SENSOR1_ECHO, PI_INPUT);
    gpioSetMode(SENSOR2_TRIGGER, PI_OUTPUT);
    gpioSetMode(SENSOR2_ECHO, PI_INPUT);
    gpioSetMode(SENSOR3_TRIGGER, PI_OUTPUT);
    gpioSetMode(SENSOR3_ECHO, PI_INPUT);

    return SUCCESS;
}

int read_config() {
    // Placeholder for reading configuration from file.
    // This function would parse the config file and set
    // sensor pin assignments, proximity zone thresholds,
    // melody frequencies/durations, and volume level.
    // For simplicity, we are using default values in this example.
    return SUCCESS;
}

int read_distance(int trigger_pin, int echo_pin, float *distance) {
    // Trigger the sensor
    gpioWrite(trigger_pin, 1);
    gpioDelay(10); // 10us trigger pulse
    gpioWrite(trigger_pin, 0);

    // Measure the echo pulse duration
    int start_tick = 0, end_tick = 0;
    while (gpioRead(echo_pin) == 0) {
        start_tick = gpioTick();
    }

    while (gpioRead(echo_pin) == 1) {
        end_tick = gpioTick();
    }

    if (start_tick == 0 || end_tick == 0) {
        return ERROR_TIMEOUT; // Timeout error
    }

    int pulse_duration = end_tick - start_tick;
    if (pulse_duration < 0) {
        return ERROR_INVALID_READING; // Invalid reading
    }

    // Calculate distance in cm (speed of sound: 343 m/s)
    *distance = (float)pulse_duration / 1000000.0 * 34300 / 2; // cm

    return SUCCESS;
}

ProximityZone determine_proximity_zone(float distance) {
    if (distance < ZONE1_THRESHOLD) {
        return ZONE_CLOSE;
    } else if (distance < ZONE2_THRESHOLD) {
        return ZONE_MEDIUM;
    } else {
        return ZONE_FAR;
    }
}

