int melody2_len = sizeof(melody2) / sizeof(melody2[0]);
int melody3_len = sizeof(melody3) / sizeof(melody3[0]);

// Define note duration (in ms)
#define NOTE_DURATION 200

// Define volume control (PWM duty cycle, 0-1000)
int volume = 500; // Initial volume

// Function to measure distance using HC-SR04
float measure_distance() {
    gpioWrite(TRIGGER_PIN, 1);
    gpioDelay(10);
    gpioWrite(TRIGGER_PIN, 0);

    uint32_t start_tick = 0;
    uint32_t end_tick = 0;

    // Wait for echo pin to go high (with timeout)
    int timeout = 1000; // Timeout after 1ms
    while (gpioRead(ECHO_PIN) == 0 && timeout > 0) {
        timeout--;
        gpioDelay(1); // Small delay to prevent busy-waiting
    }

    if (timeout == 0) {
        fprintf(stderr, "Error: Echo pin did not go high (timeout).\n");
        return -1.0; // Indicate error
    }

    start_tick = gpioTick();

    // Wait for echo pin to go low (with timeout)
    timeout = 10000; // Timeout after 10ms
    while (gpioRead(ECHO_PIN) == 1 && timeout > 0) {
        timeout--;
        gpioDelay(1); // Small delay to prevent busy-waiting
    }

    if (timeout == 0) {
        fprintf(stderr, "Error: Echo pin did not go low (timeout).\n");
        return -1.0; // Indicate error
    }

    end_tick = gpioTick();

    uint32_t diff = end_tick - start_tick;

    // Calculate distance in cm (speed of sound: 343 m/s, or 0.0343 cm/us)
    // Divide by 2 because the sound travels to the object and back
    float distance = (float)diff * 0.0343 / 2.0;

    return distance;
}

// Function to play a melody
void play_melody(int melody[], int melody_len) {
    for (int i = 0; i < melody_len; i++) {
        gpioPWM(BUZZER_PIN, volume);
        gpioSetPWMFrequency(BUZZER_PIN, melody[i]);
        gpioDelay(NOTE_DURATION);
        gpioPWM(BUZZER_PIN, 0); // Stop sound
        gpioDelay(50); // Short pause between notes
    }
}

