// Function to read calibration data from the sensor
int read_calibration_data() {
    char data[26];
    if (i2cReadI2CBlockData(i2c_handle, BME280_REG_CALIB_00, data, 26) < 0) {
        perror("Failed to read calibration data from sensor");
        return -1;
    }

    calib.dig_T1 = data[0] | (data[1] << 8);
    calib.dig_T2 = (int16_t)(data[2] | (data[3] << 8));
    calib.dig_T3 = (int16_t)(data[4] | (data[5] << 8));
    calib.dig_P1 = data[6] | (data[7] << 8);
    calib.dig_P2 = (int16_t)(data[8] | (data[9] << 8));
    calib.dig_P3 = (int16_t)(data[10] | (data[11] << 8));
    calib.dig_P4 = (int16_t)(data[12] | (data[13] << 8));
    calib.dig_P5 = (int16_t)(data[14] | (data[15] << 8));
    calib.dig_P6 = (int16_t)(data[16] | (data[17] << 8));
    calib.dig_P7 = (int16_t)(data[18] | (data[19] << 8));
    calib.dig_P8 = (int16_t)(data[20] | (data[21] << 8));
    calib.dig_P9 = (int16_t)(data[22] | (data[23] << 8));
    calib.dig_H1 = data[25];

    char data_h[7];
    if (i2cReadI2CBlockData(i2c_handle, 0xE1, data_h, 7) < 0) {
        perror("Failed to read humidity calibration data from sensor");
        return -1;
    }

    calib.dig_H2 = (int16_t)(data_h[0] | (data_h[1] << 8));
    calib.dig_H3 = data_h[2];
    calib.dig_H4 = (int16_t)((data_h[3] << 4) | (data_h[4] & 0x0F));
    calib.dig_H5 = (int16_t)((data_h[5] << 4) | ((data_h[4] >> 4) & 0x0F));
    calib.dig_H6 = data_h[6];

