    FILE *fp = fopen(SENSOR_STATE_FILE, "rb");
    if (fp == NULL) {
        perror("Failed to open sensor state file, reading from sensor");
        return read_calibration_data();
    }

    if (fread(&calib, sizeof(struct bme280_calib_data), 1, fp) != 1) {
        perror("Failed to read sensor state from file, reading from sensor");
        fclose(fp);
        return read_calibration_data();
    }

    fclose(fp);
    printf("Sensor state restored from file.\n");
    return 0;
}

// Function to read raw BME280 data
int read_bme280_data(int32_t *temperature, int32_t *pressure, int32_t *humidity) {
    char data[8];

    // Set the sensor to forced mode
    if (i2cWriteByteData(i2c_handle, BME280_REG_CTRL_MEAS, 0b00100101) < 0) { // Temperature x1, Pressure x1, Forced mode
        perror("Failed to set sensor mode");
        return -1;
    }
    if (i2cWriteByteData(i2c_handle, BME280_REG_CTRL_HUM, 0b00000101) < 0) { // Humidity x1
        perror("Failed to set humidity control");
        return -1;
    }
    gpioDelay(100); // Wait for measurement to complete (adjust as needed)

    if (i2cReadI2CBlockData(i2c_handle, BME280_REG_PRESS_MSB, data, 8) < 0) {
        perror("Failed to read data from sensor");
        return -1;
    }

    *pressure = (data[0] << 12) | (data[1] << 4) | (data[2] >> 4);
    *temperature = (data[3] << 12) | (data[4] << 4) | (data[5] >> 4);
    *humidity = (data[6] << 8) | data[7];

    return 0;
}

// Function to log sensor data to file
int log_sensor_data(float temperature, float humidity, float pressure) {
    FILE *fp = fopen(SENSOR_DATA_FILE, "a");
    if (fp == NULL) {
        perror("Failed to open sensor data file");
        return -1;
    }

    // Write header if the file is new
    fseek(fp, 0, SEEK_END);
    long fsize = ftell(fp);
    if (fsize == 0) {
        fprintf(fp, "timestamp,temperature,humidity,pressure\n");
    }

    // Get current timestamp
    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm);

    // Log the data
    fprintf(fp, "%s,%.2f,%.2f,%.2f\n", timestamp, temperature, humidity, pressure);

    fclose(fp);
    return 0;
}

// Function to save sensor state to file
int save_sensor_state() {
    FILE *fp = fopen(SENSOR_STATE_FILE, "wb");
    if (fp == NULL) {
        perror("Failed to open sensor state file for writing");
        return -1;
    }

    if (fwrite(&calib, sizeof(struct bme280_calib_data), 1, fp) != 1) {
        perror("Failed to write sensor state to file");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    printf("Sensor state saved to file.\n");
    return 0;
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, exiting gracefully...\n", signal);
    running = 0;
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C device
    i2c_handle = i2cOpen(1, BME280_I2C_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %s\n", strerror(errno));
        gpioTerminate();
        return 1;
    }

    // Restore sensor state
    if (restore_sensor_state() != 0) {
        fprintf(stderr, "Failed to restore sensor state, using default values.\n");
    }

    // Set signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    time_t last_save_time = time(NULL);

    // Main loop
    while (running) {
        int32_t raw_temperature, raw_pressure, raw_humidity;

        // Read sensor data
        if (read_bme280_data(&raw_temperature, &raw_pressure, &raw_humidity) == 0) {
            // Compensate data
            float temperature = compensate_temperature(raw_temperature) / 100.0;
            float pressure = compensate_pressure(raw_pressure) / 100.0;
            float humidity = compensate_humidity(raw_humidity) / 1024.0;

            // Log data
            if (log_sensor_data(temperature, humidity, pressure) != 0) {
                fprintf(stderr, "Failed to log sensor data.\n");
            }

            printf("Temperature: %.2f °C, Humidity: %.2f %%, Pressure: %.2f hPa\n", temperature, humidity, pressure);
        } else {
            fprintf(stderr, "Failed to read sensor data.\n");
        }

        // Save sensor state periodically (every 3600 seconds = 1 hour)
        time_t current_time = time(NULL);
        if (difftime(current_time, last_save_time) >= 3600) {
            if (save_sensor_state() != 0) {
                fprintf(stderr, "Failed to save sensor state.\n");
            }
            last_save_time = current_time;
        }

        // Sleep for 60 seconds
        gpioSleep(PI_TIME_RELATIVE, 1, 0); // seconds, microseconds
    }

    // Cleanup
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

