int bme280_init()
{
    // Reset the device
    wiringPiI2CWriteReg8(fd, BME280_REG_RESET, 0xB6);
    delay(10);

    // Set humidity oversampling to 1x
    wiringPiI2CWriteReg8(fd, BME280_REG_CTRL_HUM, 0x01);

    // Set temperature and pressure oversampling to 1x, normal mode
    wiringPiI2CWriteReg8(fd, BME280_REG_CTRL_MEAS, 0x25); //0b00100101

    delay(100); // Wait for the sensor to complete the first measurement
    return 0;
}

void bme280_read_calibration_data()
{
