float bme280_read_temperature()
{
    int32_t var1, var2;

    int32_t adc_T = (wiringPiI2CReadReg8(fd, BME280_REG_TEMP_MSB) << 12) | (wiringPiI2CReadReg8(fd, BME280_REG_TEMP_MSB + 1) << 4) | (wiringPiI2CReadReg8(fd, BME280_REG_TEMP_MSB + 2) >> 4);

