    // Read 2 bytes of data
    if (read(fd, buf, 2) == 2) {
        unsigned int raw_value = (buf[0] << 8) | buf[1];
        lux = (float)raw_value / 1.2; // Convert to lux
    } else {
        perror("Failed to read from I2C device");
        return -1.0;
    }

    return lux;
}

