        return 1;
    }

    // Set LED pin as output
    gpioSetMode(LED_PIN, PI_OUTPUT);

    // Initialize I2C
    i2c_fd = open("/dev/i2c-1", O_RDWR); // Use i2c-1 on Raspberry Pi 4
    if (i2c_fd < 0) {
