#include <wiringPi.h>
#include <signal.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <syslog.h>

#define VIBRATION_PIN 17

volatile sig_atomic_t shutdown_requested = 0;

void shutdown_system() {
    openlog("vibration_shutdown", LOG_PID | LOG_CONS, LOG_USER);
    syslog(LOG_INFO, "Vibration detected. Initiating shutdown...");

    pid_t pid = fork();

    if (pid == 0) {
        // Child process
        execlp("sudo", "sudo", "shutdown", "-h", "now", NULL);
        // If execlp fails:
        syslog(LOG_ERR, "Failed to execute shutdown command.");
        perror("execlp"); // Print error to stderr as well for debugging
        _exit(EXIT_FAILURE); // Important to use _exit in child process
    } else if (pid > 0) {
        // Parent process
        int status;
        waitpid(pid, &status, 0);
        if (WIFEXITED(status)) {
            if (WEXITSTATUS(status) != 0) {
                syslog(LOG_ERR, "Shutdown command exited with status: %d", WEXITSTATUS(status));
            }
        } else {
            syslog(LOG_ERR, "Shutdown command terminated abnormally.");
        }
    } else {
        // Fork failed
        syslog(LOG_ERR, "Failed to fork process for shutdown.");
        perror("fork");
    }

    closelog();
    exit(EXIT_FAILURE); // Exit even if shutdown fails, to prevent further triggers
}

void vibration_interrupt() {
    if (!shutdown_requested) { //debounce
        shutdown_requested = 1;
        shutdown_system();
    }
}

void signal_handler(int signum) {
    openlog("vibration_shutdown", LOG_PID | LOG_CONS, LOG_USER);
    syslog(LOG_INFO, "Caught signal %d, cleaning up and exiting...", signum);
    closelog();
    exit(0);
}

int main() {
    openlog("vibration_shutdown", LOG_PID | LOG_CONS, LOG_USER);

    if (wiringPiSetupGpio() == -1) {
        syslog(LOG_ERR, "Failed to initialize wiringPi.");
        fprintf(stderr, "Failed to initialize wiringPi. Check syslog for details.\n");
        closelog();
        return 1;
    }

    if (wiringPiISR(VIBRATION_PIN, INT_EDGE_FALLING, &vibration_interrupt) < 0) {
        syslog(LOG_ERR, "Unable to setup ISR: %m\n");
        fprintf(stderr, "Unable to setup ISR. Check syslog for details.\n");
        closelog();
        return 1;
    }

    pinMode(VIBRATION_PIN, INPUT);

    syslog(LOG_INFO, "Vibration sensor monitoring started on GPIO %d.", VIBRATION_PIN);
    printf("Vibration sensor monitoring started on GPIO %d. Press Ctrl+C to exit.\n", VIBRATION_PIN);

    signal(SIGINT, signal_handler); // Handle Ctrl+C
    signal(SIGTERM, signal_handler); // Handle termination signal

    while (1) {
        delay(100); // Keep the program running
    }

    closelog();
    return 0;
}

