// Configuration
#define CONFIG_FILE "humidity_monitor.conf"

// SHT31 Configuration
#define SHT31_I2C_ADDR 0x44
#define SHT31_MEASUREMENT_COMMAND 0x2400 // High repeatability, clock stretching disabled

// LCD1602 Configuration
#define LCD_I2C_ADDR 0x27 // Adjust if needed
#define LCD_CHR 1
#define LCD_CMD 0
#define LCD_BACKLIGHT 0x08
#define ENABLE 0b00000100 // Enable bit

// Logging Configuration
#define LOG_FILE "humidity_log.json"

// Global Variables
int i2c_handle = -1;
int lcd_handle = -1;
int log_fd = -1;
json_t *log_array = NULL;
config_t cfg;

// Configuration Parameters (Default Values)
int sht31_address = SHT31_I2C_ADDR;
int lcd_address = LCD_I2C_ADDR;
int logging_interval = 5; // seconds

// Function Prototypes
void cleanup(int signal);
int init_i2c();
int init_lcd();
int read_sht31(float *temperature, float *humidity);
void display_data(float temperature, float humidity);
void log_data(float temperature, float humidity);
void update_data_callback();
void lcd_byte(int bits, int mode);
void lcd_string(const char *s);
void lcd_init();
void lcd_clear();
void load_configuration();

// Helper function to print error messages to stderr
void error_message(const char *message) {
    fprintf(stderr, "%s\n", message);
}

// Helper function to print debug messages to stdout
void debug_message(const char *message) {
    printf("%s\n", message);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        error_message("pigpio initialisation failed");
        return 1;
    }

    // Load Configuration
    load_configuration();

    // Signal Handling
    signal(SIGINT, cleanup);
    signal(SIGTERM, cleanup);

    // Initialize I2C
    if (init_i2c() != 0) {
        error_message("I2C initialisation failed");
        cleanup(0);
        return 1;
    }

    // Initialize LCD
    if (init_lcd() != 0) {
        fprintf(stderr, "LCD initialisation failed, continuing without LCD\n");
    }

    // Initialize JSON logging
    log_array = json_array();
    if (log_array == NULL) {
        error_message("Failed to create JSON array");
        cleanup(0);
        return 1;
    }

    // Set up timer callback for data acquisition and display
    gpioSetTimerFuncEx(0, logging_interval * 1000, update_data_callback, NULL);

    // Main loop (non-blocking)
    while (1) {
        gpioDelay(100); // Reduce CPU usage
    }

    return 0;
}

void load_configuration() {
    config_init(&cfg);

    /* Read the file. If there is an error, report it and exit. */
    if(! config_read_file(&cfg, CONFIG_FILE))
    {
        fprintf(stderr, "%s:%d - %s\n", config_error_file(&cfg),
                config_error_line(&cfg), config_error_text(&cfg));
        config_destroy(&cfg);
        // Use default values if config file fails to load.
        fprintf(stderr, "Failed to load config file, using default values.\n");
        return;
    }

    config_lookup_int(&cfg, "sht31_address", &sht31_address);
    config_lookup_int(&cfg, "lcd_address", &lcd_address);
    config_lookup_int(&cfg, "logging_interval", &logging_interval);

    printf("Configuration loaded:\n");
    printf("  SHT31 Address: 0x%02x\n", sht31_address);
    printf("  LCD Address: 0x%02x\n", lcd_address);
    printf("  Logging Interval: %d seconds\n", logging_interval);

    config_destroy(&cfg);
}

void cleanup(int signal) {
    printf("Cleaning up and exiting...\n");

    // Close I2C connection
    if (i2c_handle >= 0) {
        i2cClose(i2c_handle);
    }

    // Clear LCD display
    if (lcd_handle >= 0) {
        lcd_clear();
    }

    // Release file lock and close log file
    if (log_fd >= 0) {
        flock(log_fd, LOCK_UN);
        close(log_fd);
    }

    // Free JSON array
    if (log_array != NULL) {
        json_decref(log_array);
    }

    // Stop pigpio
    gpioTerminate();

    exit(0);
}

int init_i2c() {
    int retries = 0;
    while (retries < 3) {
        i2c_handle = i2cOpen(1, sht31_address, 0); // Bus 1, address, flags
        if (i2c_handle >= 0) {
            printf("I2C connection established with SHT31 at address 0x%02x\n", sht31_address);
            return 0; // Success
        } else {
            fprintf(stderr, "I2C open failed (attempt %d): %d\n", retries + 1, i2c_handle);
            retries++;
            gpioDelay(100); // Wait before retrying
        }
    }
    fprintf(stderr, "I2C initialisation failed after multiple retries. Attempting pigpio restart.\n");
    gpioCfgSetInternals(PI_INIT_FAILED); // Attempt pigpio restart
    return -1; // Failure
}

int init_lcd() {
    int retries = 0;
    while (retries < 3) {
        lcd_handle = i2cOpen(1, lcd_address, 0); // Bus 1, address, flags
        if (lcd_handle >= 0) {
            printf("I2C connection established with LCD at address 0x%02x\n", lcd_address);
            lcd_init();
            lcd_clear();
            lcd_string("Initializing...");
            return 0; // Success
        } else {
            fprintf(stderr, "LCD I2C open failed (attempt %d): %d\n", retries + 1, lcd_handle);
            retries++;
            gpioDelay(100); // Wait before retrying
        }
    }
    return -1; // Failure
}

int read_sht31(float *temperature, float *humidity) {
    char write_data[2] = {(SHT31_MEASUREMENT_COMMAND >> 8) & 0xFF, SHT31_MEASUREMENT_COMMAND & 0xFF};
    char read_data[6];
    int result;

    result = i2cWriteDevice(i2c_handle, write_data, 2);
    if (result != 2) {
        fprintf(stderr, "Error writing to SHT31: %d\n", result);
        return -1;
    }

    gpioDelay(20); // Wait for measurement (adjust if needed)

    result = i2cReadDevice(i2c_handle, read_data, 6);
    if (result != 6) {
        fprintf(stderr, "Error reading from SHT31: %d\n", result);
        return -1;
    }

    // Convert data
    uint16_t temp_raw = (read_data[0] << 8) | read_data[1];
    uint16_t hum_raw = (read_data[3] << 8) | read_data[4];

    *temperature = -45.0 + (175.0 * (float)temp_raw / 65535.0);
    *humidity = 100.0 * (float)hum_raw / 65535.0;

    // Validate readings
    if (*temperature < -40.0 || *temperature > 125.0) {
        fprintf(stderr, "Warning: Temperature out of range: %.2f\n", *temperature);
        return -1;
    }
    if (*humidity < 0.0 || *humidity > 100.0) {
        fprintf(stderr, "Warning: Humidity out of range: %.2f\n", *humidity);
        return -1;
    }

    return 0;
}

void display_data(float temperature, float humidity) {
    if (lcd_handle < 0) return; // Don't attempt to display if LCD init failed

    char temp_str[20];
    char hum_str[20];

    snprintf(temp_str, sizeof(temp_str), "Temp: %.2f C", temperature);
    snprintf(hum_str, sizeof(hum_str), "Hum: %.2f %%", humidity);

    lcd_clear();
    lcd_string(temp_str);
    lcd_byte(0xC0, LCD_CMD); // Move cursor to second line
    lcd_string(hum_str);
}

void log_data(float temperature, float humidity) {
    // Get current timestamp
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[32];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%dT%H:%M:%SZ", t); // ISO 8601

    // Create JSON object
    json_t *reading = json_object();
    json_object_set_new(reading, "timestamp", json_string(timestamp));
    json_object_set_new(reading, "temperature", json_real(temperature));
    json_object_set_new(reading, "humidity", json_real(humidity));

    // Append to JSON array
    json_array_append_new(log_array, reading);

    // Open log file with locking
    log_fd = open(LOG_FILE, O_WRONLY | O_CREAT | O_APPEND, 0644);
    if (log_fd < 0) {
        fprintf(stderr, "Failed to open log file: %s\n", strerror(errno));
        return;
    }

    // Acquire exclusive lock
    if (flock(log_fd, LOCK_EX) < 0) {
        fprintf(stderr, "Failed to acquire lock on log file: %s\n", strerror(errno));
        close(log_fd);
        return;
    }

    // Write JSON data to file
    FILE *log_file = fdopen(log_fd, "w");
    if (log_file == NULL) {
        fprintf(stderr, "Failed to open log file as FILE*: %s\n", strerror(errno));
        flock(log_fd, LOCK_UN);
        close(log_fd);
        return;
    }
    json_dumpf(log_array, log_file, JSON_INDENT(4)); // Pretty print
    fprintf(log_file, "\n"); // Add newline

    // Release lock and close file
    fclose(log_file);
    flock(log_fd, LOCK_UN);
    close(log_fd);
    log_fd = -1; // Reset log_fd
}

void update_data_callback() {
    float temperature, humidity;

    if (read_sht31(&temperature, &humidity) == 0) {
        printf("Temperature: %.2f C, Humidity: %.2f %%\n", temperature, humidity);
        display_data(temperature, humidity);
        log_data(temperature, humidity);
    }
}

// LCD functions (Simplified for brevity, adjust as needed)
void lcd_byte(int bits, int mode) {
    // Send byte to data pins
    // bits = the data
    // mode = 1 for data, 0 for command

    int bits_high = mode | (bits & 0xF0) | LCD_BACKLIGHT;
    int bits_low = mode | ((bits << 4) & 0xF0) | LCD_BACKLIGHT;

    i2cWriteByteData(lcd_handle, bits_high,0); // original code
    gpioDelay(1); // Original code
    i2cWriteByteData(lcd_handle, (bits_high | ENABLE),0); // original code
    gpioDelay(1); // Original code
    i2cWriteByteData(lcd_handle, (bits_high & ~ENABLE),0); // original code
    gpioDelay(1); // Original code

    // Low bits
    i2cWriteByteData(lcd_handle, bits_low,0); // original code
    gpioDelay(1); // Original code
    i2cWriteByteData(lcd_handle, (bits_low | ENABLE),0); // original code
    gpioDelay(1); // Original code
    i2cWriteByteData(lcd_handle, (bits_low & ~ENABLE),0); // original code
    gpioDelay(1); // Original code
}

void lcd_string(const char *s) {
    while (*s) {
        lcd_byte(*s++, LCD_CHR);
    }
}

void lcd_init() {
    // Initialise display
    lcd_byte(0x33, LCD_CMD); // Initialise
    lcd_byte(0x32, LCD_CMD); // Initialise
    lcd_byte(0x06, LCD_CMD); // Cursor move direction
    lcd_byte(0x0C, LCD_CMD); // Turn on display, cursorUnderline Off, blinkingOff
    lcd_byte(0x28, LCD_CMD); // Data length, number of lines, font size
    lcd_byte(0x01, LCD_CMD); // Clear display
    gpioDelay(500);
}

void lcd_clear() {
    lcd_byte(0x01, LCD_CMD);
    gpioDelay(500);
}

