#include <linux/i2c-dev.h>
#include <errno.h>

#include <jansson.h>

// SHT31 I2C address
#define SHT31_ADDR 0x44

// LCD1602 I2C address (adjust if needed)
#define LCD_ADDR 0x27
#define LCD_CHR 1
#define LCD_CMD 0

#define LINE1 0x80 // Address of the first line
#define LINE2 0xC0 // Address of the second line

#define LCD_BACKLIGHT   0x08  // On
//define LCD_BACKLIGHT 0x00  // Off

#define ENABLE  0b00000100 // Enable bit

// I2C file descriptor
int i2c_fd;

// Function prototypes
int init_i2c(int addr);
int sht31_read_temperature_humidity(float *temperature, float *humidity);
int lcd_init();
void lcd_byte(int bits, int mode);
void lcd_string(const char *s);
void lcd_clear();
void lcd_backlight(int on);
void log_data(float temperature, float humidity);

int main()
{
    float temperature, humidity;

    // Initialize pigpio
    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Initialize I2C
    if ((i2c_fd = init_i2c(SHT31_ADDR)) < 0)
    {
        fprintf(stderr, "Failed to initialize I2C for SHT31\n");
        gpioTerminate();
        return 1;
    }

    // Initialize LCD
    if (lcd_init() < 0)
    {
        fprintf(stderr, "Failed to initialize LCD\n");
        gpioTerminate();
        close(i2c_fd);
        return 1;
    }

    lcd_backlight(1); // Turn on backlight

    while (1)
    {
        // Read temperature and humidity
        if (sht31_read_temperature_humidity(&temperature, &humidity) == 0)
        {
            // Print to console
            printf("Temperature: %.2f °C, Humidity: %.2f %%\n", temperature, humidity);

            // Display on LCD
            char temp_str[20];
            char hum_str[20];

            snprintf(temp_str, sizeof(temp_str), "Temp: %.2f C", temperature);
            snprintf(hum_str, sizeof(hum_str), "Hum: %.2f %%", humidity);

            lcd_clear();
            lcd_string(temp_str);
            lcd_byte(LINE2, LCD_CMD);
            lcd_string(hum_str);

            // Log data to JSON file
            log_data(temperature, humidity);
        }
        else
        {
            fprintf(stderr, "Failed to read SHT31 data\n");
        }

        gpioDelay(2000); // Wait 2 seconds
    }

    // Clean up
    lcd_clear();
    lcd_backlight(0); // Turn off backlight
    close(i2c_fd);
    gpioTerminate();

    return 0;
}

int init_i2c(int addr)
{
    int fd;
    char filename[20];

    snprintf(filename, 19, "/dev/i2c-1");
    fd = open(filename, O_RDWR);
    if (fd < 0)
    {
        fprintf(stderr, "Failed to open i2c device: %s\n", strerror(errno));
        return -1;
    }

    if (ioctl(fd, I2C_SLAVE, addr) < 0)
    {
        fprintf(stderr, "Failed to acquire bus access and/or talk to slave: %s\n", strerror(errno));
        close(fd);
        return -1;
    }

    return fd;
}

int sht31_read_temperature_humidity(float *temperature, float *humidity)
{
    // Send measurement command (High repeatability, Clock stretching enabled)
    uint8_t cmd[2] = {0x24, 0x00};
    if (write(i2c_fd, cmd, 2) != 2)
    {
        fprintf(stderr, "Failed to write to i2c device: %s\n", strerror(errno));
        return -1;
    }

    // Wait for measurement (at least 10 ms)
    gpioDelay(15);

    // Read 6 bytes of data (Temp MSB, Temp LSB, Temp CRC, Hum MSB, Hum LSB, Hum CRC)
    uint8_t data[6];
    if (read(i2c_fd, data, 6) != 6)
    {
        fprintf(stderr, "Failed to read from i2c device: %s\n", strerror(errno));
        return -1;
    }

    // Convert data
    int temp_raw = (data[0] << 8) | data[1];
    int hum_raw = (data[3] << 8) | data[4];

    // Calculate temperature [°C]
    *temperature = -45.0 + (175.0 * (float)temp_raw / 65535.0);

    // Calculate relative humidity [%RH]
    *humidity = 100.0 * (float)hum_raw / 65535.0;

    return 0;
}

int lcd_init()
{
    int i2c_lcd_fd = init_i2c(LCD_ADDR);
    if (i2c_lcd_fd < 0) {
        fprintf(stderr, "Failed to initialize I2C for LCD\n");
        return -1;
    }

    // 4 bit initialisation
    gpioDelay(50);  // wait 50ms
    lcd_byte(0x30, LCD_CMD);
    gpioDelay(5);  // wait 5ms
    lcd_byte(0x30, LCD_CMD);
    gpioDelay(1);  // wait 1ms
    lcd_byte(0x30, LCD_CMD);
    gpioDelay(1); // wait 1ms
    lcd_byte(0x20, LCD_CMD); // 4bit mode
    gpioDelay(1); // wait 1ms

    // Function set mode
    lcd_byte(0x28, LCD_CMD); // Function set --> DL=0 (4 bit mode), N=1 (2 line display), F=0 (5x8 characters)
    gpioDelay(1); // wait 1ms

    // Display control mode
    lcd_byte(0x08, LCD_CMD); //Display on/off control --> D=0, C=0, B=0  ---> display off
    gpioDelay(1); // wait 1ms

    // Clear display
    lcd_byte(0x01, LCD_CMD);  // clear display
    gpioDelay(2); // wait 2ms

    // Entry mode set
    lcd_byte(0x06, LCD_CMD); //Entry mode set --> I/D = 1 (increment cursor), S = 0 (no shift)
    gpioDelay(1); // wait 1ms

    // Display on
    lcd_byte(0x0C, LCD_CMD); //Display on/off control --> D=1, C=0, B=0  ---> display on, cursor off, blink off

    close(i2c_lcd_fd);
    return 0;
}

void lcd_byte(int bits, int mode)
{
    int bits_high = mode | (bits & 0xF0) | LCD_BACKLIGHT;
    int bits_low = mode | ((bits << 4) & 0xF0) | LCD_BACKLIGHT;

    int i2c_lcd_fd = init_i2c(LCD_ADDR);
    if (i2c_lcd_fd < 0) {
        fprintf(stderr, "Failed to initialize I2C for LCD in lcd_byte\n");
        return;
    }

    // High bits
    write(i2c_lcd_fd, (char *)&bits_high, 1);
    gpioDelay(1); // wait 1ms
    bits_high |= ENABLE;
    write(i2c_lcd_fd, (char *)&bits_high, 1);
    gpioDelay(1); // wait 1ms
    bits_high &= ~ENABLE;
    write(i2c_lcd_fd, (char *)&bits_high, 1);
    gpioDelay(1); // wait 1ms

    // Low bits
    write(i2c_lcd_fd, (char *)&bits_low, 1);
    gpioDelay(1); // wait 1ms
    bits_low |= ENABLE;
    write(i2c_lcd_fd, (char *)&bits_low, 1);
    gpioDelay(1); // wait 1ms
    bits_low &= ~ENABLE;
    write(i2c_lcd_fd, (char *)&bits_low, 1);
    gpioDelay(1); // wait 1ms

    close(i2c_lcd_fd);
}

void lcd_string(const char *s)
{
    while (*s)
    {
        lcd_byte(*s, LCD_CHR);
        s++;
    }
}

void lcd_clear()
{
    lcd_byte(0x01, LCD_CMD);
    gpioDelay(2); // wait 2ms
}

void lcd_backlight(int on)
{
    int i2c_lcd_fd = init_i2c(LCD_ADDR);
    if (i2c_lcd_fd < 0) {
        fprintf(stderr, "Failed to initialize I2C for LCD in lcd_backlight\n");
        return;
    }

    int backlight_state = on ? LCD_BACKLIGHT : 0;
    int data = backlight_state;

    write(i2c_lcd_fd, (char *)&data, 1);
    close(i2c_lcd_fd);
}

void log_data(float temperature, float humidity)
{
    json_t *root = json_object();
    json_t *data = json_object();

    // Get current timestamp
    time_t now = time(NULL);
    struct tm *tstruct = localtime(&now);
    char buf[80];
    strftime(buf, sizeof(buf), "%Y-%m-%d.%X", tstruct);

    // Add data to JSON object
    json_object_set_new(data, "timestamp", json_string(buf));
    json_object_set_new(data, "temperature", json_real(temperature));
    json_object_set_new(data, "humidity", json_real(humidity));

    // Add data array to root object
    json_object_set_new(root, "data", data);

    // Write JSON to file
    json_dump_file(root, "humidity_log.json", JSON_INDENT(4));

    // Free JSON object
    json_decref(root);
}

