int i2c_write_reg(int handle, uint8_t reg, uint8_t value) {
    char buf[2];
    buf[0] = reg;
    buf[1] = value;
    if (i2cWriteI2C(handle, buf, 2) != 2) {
        fprintf(stderr, "Error writing to I2C register 0x%02X\n", reg);
        return -1;
    }
    return 0;
}

// Function to read a byte from an I2C register
int i2c_read_reg(int handle, uint8_t reg, uint8_t *value) {
    if (i2cWriteI2C(handle, (char *)&reg, 1) != 1) {
        fprintf(stderr, "Error writing register address for read\n");
        return -1;
    }
    if (i2cReadI2C(handle, (char *)value, 1) != 1) {
        fprintf(stderr, "Error reading from I2C register 0x%02X\n", reg);
        return -1;
    }
    return 0;
}

// Function to read a 16-bit value from two I2C registers
int i2c_read_16(int handle, uint8_t reg_msb, int16_t *value) {
    uint8_t msb, lsb;
    if (i2c_read_reg(handle, reg_msb, &msb) < 0) return -1;
    if (i2c_read_reg(handle, reg_msb + 1, &lsb) < 0) return -1;
    *value = (int16_t)((msb << 8) | lsb);
    return 0;
}

