        return 1;
    }

    // Set up interrupt
    if (wiringPiISR(GPIO_PIN, INT_EDGE_BOTH, interruptHandler) < 0) {
        fprintf(stderr, "Unable to setup ISR: %s\n", strerror(errno));
        return 1;
    }

