        printLastEvents(&eventBuffer);
    }

    // Cleanup (never reached in this example, but good practice)
    pthread_mutex_destroy(&bufferMutex);
    return 0;
}

// Initialize the circular buffer
void initCircularBuffer(CircularBuffer *cb) {
    cb->head = 0;
    cb->tail = 0;
    cb->count = 0;
}

// Insert an event into the circular buffer
int insertEvent(CircularBuffer *cb, time_t timestamp, int state) {
    pthread_mutex_lock(&bufferMutex);

    cb->buffer[cb->head].timestamp = timestamp;
    cb->buffer[cb->head].state = state;

    cb->head = (cb->head + 1) % BUFFER_SIZE;

    if (cb->count == BUFFER_SIZE) {
        cb->tail = (cb->tail + 1) % BUFFER_SIZE;
    } else {
        cb->count++;
    }

    pthread_mutex_unlock(&bufferMutex);
    return 0;
}

// Get an event from the circular buffer at a specific index
int getEvent(CircularBuffer *cb, int index, Event *event) {
    pthread_mutex_lock(&bufferMutex);

    if (index < 0 || index >= cb->count) {
        pthread_mutex_unlock(&bufferMutex);
        return -1; // Invalid index
    }

    int actualIndex = (cb->tail + index) % BUFFER_SIZE;
    *event = cb->buffer[actualIndex];

    pthread_mutex_unlock(&bufferMutex);
    return 0;
}

