// Debounce delay in milliseconds
#define DEBOUNCE_DELAY 50

// Function to get current timestamp
char* get_timestamp() {
    time_t rawtime;
    struct tm *timeinfo;
    time(&rawtime);
    timeinfo = localtime(&rawtime);

    char *timestamp = (char*)malloc(20 * sizeof(char));
    if (timestamp == NULL) {
        perror("Failed to allocate memory for timestamp");
        return NULL;
    }

    strftime(timestamp, 20, "%Y-%m-%d %H:%M:%S", timeinfo);
    return timestamp;
}

// Function to log lock events
void log_event(int lock_id, char *action) {
    FILE *fp = fopen("lock_events.log", "a");
    if (fp == NULL) {
        perror("Failed to open log file");
        return;
    }

    char *timestamp = get_timestamp();
    if (timestamp != NULL) {
        fprintf(fp, "%s - Lock %d: %s\n", timestamp, lock_id, action);
        free(timestamp);
    }

    fclose(fp);
}

// Function to toggle a lock
void toggle_lock(int lock_pin, int lock_id) {
    int current_state = gpioRead(lock_pin);
    if (current_state == 0) { // Assuming 0 is locked
        gpioWrite(lock_pin, 1); // Unlock
        log_event(lock_id, "Unlocked");
        printf("Lock %d unlocked\n", lock_id);
    } else {
        gpioWrite(lock_pin, 0); // Lock
        log_event(lock_id, "Locked");
        printf("Lock %d locked\n", lock_id);
    }
}

// Callback function for button press
void button_callback(int gpio, int level, uint32_t tick) {
    static uint32_t last_tick = 0;

    // Debounce the button
    if (gpioTickDiff(last_tick, tick) > DEBOUNCE_DELAY * 1000) {
        last_tick = tick;
        printf("Button pressed\n");
        toggle_lock(LOCK1_PIN, 1);
        toggle_lock(LOCK2_PIN, 2);
    }
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(BUTTON_PIN, PI_INPUT);
    gpioSetMode(LOCK1_PIN, PI_OUTPUT);
    gpioSetMode(LOCK2_PIN, PI_OUTPUT);

    // Set pull-up resistor on the button pin
    gpioSetPullUpDown(BUTTON_PIN, PI_PUD_UP);

    // Initialize locks to locked state (LOW)
    gpioWrite(LOCK1_PIN, 0);
    gpioWrite(LOCK2_PIN, 0);

