    if (gpioSetAlertFunc(BUTTON_PIN, button_callback) != 0) {
        fprintf(stderr, "Failed to set alert function\n");
        gpioTerminate();
        return 1;
    }

    printf("Door lock control program started. Press Ctrl+C to exit.\n");

    // Keep the program running
    while (1) {
        gpioDelay(100); // Check every 100ms
    }

