#include <pigpio.h>
#include <errno.h>

// Configuration
#define NUM_SENSORS 3
#define NUM_LEDS 3
#define I2C_BUS 1

// Sensor Addresses
const int sensor_addresses[NUM_SENSORS] = {0x5A, 0x5B, 0x5C};

// LED GPIOs
const int led_gpios[NUM_LEDS] = {17, 22, 27};

// PWM Frequency
#define PWM_FREQUENCY 1000

// Fading Step
#define FADE_STEP 5

// Fading Delay (milliseconds)
#define FADE_DELAY 20

// Global variables
int i2c_handles[NUM_SENSORS];
FILE *error_log;
volatile sig_atomic_t terminate = 0;

// Function prototypes
int i2c_read_data(int handle, int reg);
int i2c_write_data(int handle, int reg, int data);
int init_i2c_sensors();
void init_leds();
void cleanup();
void signal_handler(int signal);
void log_error(const char *message);
int read_touch_data(int sensor_index);
void fade_led(int gpio);

// Function to log errors with timestamps
void log_error(const char *message) {
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    fprintf(error_log, "[%d-%02d-%02d %02d:%02d:%02d] %s\n",
            t->tm_year + 1900, t->tm_mon + 1, t->tm_mday, t->tm_hour, t->tm_min, t->tm_sec, message);
    fflush(error_log);
}

// Function to read data from I2C
int i2c_read_data(int handle, int reg) {
    char buf[1];
    buf[0] = reg;
    if (i2cWriteByte(handle, reg) != 0) {
        log_error("I2C Write Error (register select)");
        return -1;
    }
    int bytes_read = i2cReadByte(handle);
    if (bytes_read < 0) {
        log_error("I2C Read Error");
        return -1;
    }
    return bytes_read;
}

// Function to write data to I2C
int i2c_write_data(int handle, int reg, int data) {
    if (i2cWriteByteData(handle, reg, data) != 0) {
        char error_message[100];
        snprintf(error_message, sizeof(error_message), "I2C Write Error (reg: 0x%02X, data: 0x%02X)", reg, data);
        log_error(error_message);
        return -1;
    }
    return 0;
}

// Function to initialize I2C sensors
int init_i2c_sensors() {
    for (int i = 0; i < NUM_SENSORS; i++) {
        i2c_handles[i] = i2cOpen(I2C_BUS, sensor_addresses[i], 0);
        if (i2c_handles[i] < 0) {
            char error_message[50];
            snprintf(error_message, sizeof(error_message), "Failed to open I2C device at address 0x%02X", sensor_addresses[i]);
            log_error(error_message);
            return -1;
        }

        // MPR121 Initialization Sequence (Example)
        i2c_write_data(i2c_handles[i], 0x2B, 0x01); // Reset
        gpioDelay(10000); // 10ms delay
        i2c_write_data(i2c_handles[i], 0x5E, 0xC0); // Electrode Configuration
        i2c_write_data(i2c_handles[i], 0x5D, 0x24); // Global Sensing Enable
        i2c_write_data(i2c_handles[i], 0x2B, 0x10); // Enable running mode

    }
    return 0;
}

// Function to initialize LEDs
void init_leds() {
    for (int i = 0; i < NUM_LEDS; i++) {
        gpioSetMode(led_gpios[i], PI_OUTPUT);
        gpioPWM(led_gpios[i], 0); // Initialize PWM to 0
        gpioSetPWMfrequency(led_gpios[i], PWM_FREQUENCY);
    }
}

// Function to read touch data from a specific sensor
int read_touch_data(int sensor_index) {
    if (sensor_index < 0 || sensor_index >= NUM_SENSORS) {
        log_error("Invalid sensor index");
        return 0; // Or some error value
    }

    int handle = i2c_handles[sensor_index];
    int touch_status = i2c_read_data(handle, 0x00); // Read electrode touch status

    if (touch_status < 0) {
        char error_message[50];
        snprintf(error_message, sizeof(error_message), "Error reading touch data from sensor %d", sensor_index);
        log_error(error_message);
        return 0; // Or some error value
    }

    // Validate touch data (example: check if any electrode is touched)
    if (touch_status > 0) {
        return touch_status; // Return the raw touch status
    } else {
        return 0; // No touch detected
    }
}

// Function to fade an LED using PWM
void fade_led(int gpio) {
    int duty_cycle = 0;
    int direction = 1; // 1 for increasing, -1 for decreasing

    while (!terminate) {
        gpioPWM(gpio, duty_cycle);
        duty_cycle += FADE_STEP * direction;

        if (duty_cycle >= 255) {
            duty_cycle = 255;
            direction = -1;
        } else if (duty_cycle <= 0) {
            duty_cycle = 0;
            direction = 1;
        }

        gpioDelay(FADE_DELAY * 1000); // Convert milliseconds to microseconds
    }
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    if (signal == SIGINT || signal == SIGTERM) {
        printf("Received signal %d, terminating...\n", signal);
        terminate = 1;
    }
}

// Cleanup function to release resources
void cleanup() {
    printf("Cleaning up...\n");
    // Stop PWM on all LEDs and set them to low
    for (int i = 0; i < NUM_LEDS; i++) {
        gpioPWM(led_gpios[i], 0);
        gpioSetMode(led_gpios[i], PI_INPUT); // Set to input to avoid drawing current
    }

    // Close I2C connections
    for (int i = 0; i < NUM_SENSORS; i++) {
        i2cClose(i2c_handles[i]);
    }

    // Close error log file
    if (error_log != NULL) {
        fclose(error_log);
    }

    // Stop pigpio
    gpioTerminate();

    printf("Cleanup complete. Exiting.\n");
}

int main() {
    // Initialize error logging
    error_log = fopen("touch_sensor_errors.log", "a");
    if (error_log == NULL) {
        perror("Failed to open error log file");
        return 1;
    }

    // Register signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        log_error("pigpio initialisation failed");
        fclose(error_log);
        return 1;
    }

    // Initialize I2C sensors
    if (init_i2c_sensors() != 0) {
        log_error("I2C sensor initialisation failed");
        cleanup();
        return 1;
    }

    // Initialize LEDs
    init_leds();

    // Seed the random number generator
    srand(time(NULL));

    printf("Touch sensor application started. Press Ctrl+C to exit.\n");

    while (!terminate) {
        // Check each sensor for touch events
        for (int i = 0; i < NUM_SENSORS; i++) {
            int touch_data = read_touch_data(i);
            if (touch_data > 0) {
                // Touch detected on sensor i
                printf("Touch detected on sensor %d\n", i);

                // Randomly select an LED
                int led_index = rand() % NUM_LEDS;
                int selected_led = led_gpios[led_index];

                printf("Fading LED on GPIO %d\n", selected_led);

                // Fade the selected LED
                fade_led(selected_led);

                // Small delay to prevent rapid triggering
                gpioDelay(200000); // 200ms

                break; // Exit the sensor loop after detecting a touch
            }
        }
        gpioDelay(10000); // Short delay (10ms) between sensor reads
    }

    // Cleanup and exit
    cleanup();
    return 0;
}

