// MPR121 I2C Address
#define MPR121_ADDR 0x5A

// MPR121 Register Addresses
#define MPR121_TOUCHSTATUS_L 0x00
#define MPR121_TOUCHSTATUS_H 0x01
#define MPR121_ELECTRODE0_LSB 0x04

// LED GPIO Pins
#define LED1 17
#define LED2 22
#define LED3 27

// Function to read a register from the MPR121
int readRegister(int handle, uint8_t reg)
{
    char buf[1];
    buf[0] = reg;
    if (i2cWriteDevice(handle, buf, 1) != 0) {
        fprintf(stderr, "Error writing to I2C device\n");
        return -1;
    }
    if (i2cReadDevice(handle, buf, 1) != 0) {
        fprintf(stderr, "Error reading from I2C device\n");
        return -1;
    }
    return buf[0];
}

// Function to write a register to the MPR121
int writeRegister(int handle, uint8_t reg, uint8_t value)
{
    char buf[2];
    buf[0] = reg;
    buf[1] = value;
    if (i2cWriteDevice(handle, buf, 2) != 0) {
        fprintf(stderr, "Error writing to I2C device\n");
        return -1;
    }
    return 0;
}

// Function to initialize the MPR121
int initMPR121(int handle)
{
    // Stop Mode
    if (writeRegister(handle, 0x80, 0x63) != 0) return -1;
    gpioDelay(5000); //5ms delay

    // Configuration
    if (writeRegister(handle, 0x5B, 0x0C) != 0) return -1; // Set Electrode Filter Control
    if (writeRegister(handle, 0x5C, 0x0C) != 0) return -1; // Set Electrode Filter Control
    if (writeRegister(handle, 0x5D, 0x01) != 0) return -1; // Set Electrode Filter Control
    if (writeRegister(handle, 0x5E, 0x01) != 0) return -1; // Set Electrode Filter Control
    if (writeRegister(handle, 0x5F, 0x00) != 0) return -1; // Set Electrode Filter Control
    if (writeRegister(handle, 0x60, 0x00) != 0) return -1; // Set Electrode Filter Control

    if (writeRegister(handle, 0x41, 0x0F) != 0) return -1; // Touch Threshold
    if (writeRegister(handle, 0x42, 0x0A) != 0) return -1; // Release Threshold

    if (writeRegister(handle, 0x5E, 0x10) != 0) return -1; // Debounce
    if (writeRegister(handle, 0x5F, 0x10) != 0) return -1; // Debounce

    // Enable all electrodes
    if (writeRegister(handle, 0x5B, 0x0C) != 0) return -1;
    if (writeRegister(handle, 0x5C, 0x0C) != 0) return -1;
    if (writeRegister(handle, 0x5D, 0x01) != 0) return -1;
    if (writeRegister(handle, 0x5E, 0x01) != 0) return -1;
    if (writeRegister(handle, 0x5F, 0x00) != 0) return -1;
    if (writeRegister(handle, 0x60, 0x00) != 0) return -1;

    // Start in run mode
    if (writeRegister(handle, 0x80, 0x10) != 0) return -1; // Enable all electrodes

    return 0;
}

// Function to fade an LED using PWM
void fadeLED(int ledPin)
{
    for (int i = 0; i <= 1000; i += 10) {
        gpioPWM(ledPin, i);
        gpioDelay(5);
    }
    for (int i = 1000; i >= 0; i -= 10) {
        gpioPWM(ledPin, i);
        gpioDelay(5);
    }
    gpioPWM(ledPin, 0);
}

int main()
{
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    int i2cHandle = i2cOpen(1, MPR121_ADDR, 0); // Bus 1, address 0x5A, no flags
    if (i2cHandle < 0) {
        fprintf(stderr, "Error opening I2C device: %d\n", i2cHandle);
        gpioTerminate();
        return 1;
    }

    if (initMPR121(i2cHandle) != 0) {
        fprintf(stderr, "MPR121 initialisation failed\n");
        i2cClose(i2cHandle);
        gpioTerminate();
        return 1;
    }

    // Set LED pins as outputs
    gpioSetMode(LED1, PI_OUTPUT);
    gpioSetMode(LED2, PI_OUTPUT);
    gpioSetMode(LED3, PI_OUTPUT);

    // Set PWM range
    gpioSetPWMrange(LED1, 1000);
    gpioSetPWMrange(LED2, 1000);
    gpioSetPWMrange(LED3, 1000);

    srand(time(NULL)); // Seed the random number generator

    printf("MPR121 and LEDs initialized. Waiting for touch events...\n");

    while (1) {
        int touchStatusLow = readRegister(i2cHandle, MPR121_TOUCHSTATUS_L);
        int touchStatusHigh = readRegister(i2cHandle, MPR121_TOUCHSTATUS_H);

        if (touchStatusLow < 0 || touchStatusHigh < 0) {
            fprintf(stderr, "Error reading touch status. Retrying...\n");
            gpioDelay(100); // Small delay before retrying
            continue;
        }

        int touchStatus = (touchStatusHigh << 8) | touchStatusLow;

        if (touchStatus > 0) {
            // A touch event occurred
            int randomLED = (rand() % 3); // Generate a random number between 0 and 2
            int ledPin;

            switch (randomLED) {
                case 0:
                    ledPin = LED1;
                    break;
                case 1:
                    ledPin = LED2;
                    break;
                case 2:
                    ledPin = LED3;
                    break;
                default:
                    ledPin = LED1; // Should not happen, but handle it anyway
                    break;
            }

            printf("Touch detected! Fading LED on GPIO %d\n", ledPin);
            fadeLED(ledPin);

            // Debounce delay
            gpioDelay(500); // Wait 500ms to avoid multiple triggers from a single touch
        }

        gpioDelay(10); // Small delay to avoid busy-waiting
    }

    i2cClose(i2cHandle);
    gpioTerminate();
    return 0;
}

