#define CLOCK_PIN  1   // GPIO 18 (WiringPi pin 1)
#define DATA_PIN   2   // GPIO 27 (WiringPi pin 2)

// Define the segment patterns for each digit (0-9)
const unsigned char digits[] = {
    0x3F, // 0
    0x06, // 1
    0x5B, // 2
    0x4F, // 3
    0x66, // 4
    0x6D, // 5
    0x7D, // 6
    0x07, // 7
    0x7F, // 8
    0x6F  // 9
};

// Function to shift out the data to the 74HC595
void shiftOut(unsigned char dataPin, unsigned char clockPin, unsigned char dataOut) {
    int i;

    for (i = 0; i < 8; i++) {
        digitalWrite(dataPin, (dataOut >> (7 - i)) & 0x01); // Send bit
        digitalWrite(clockPin, HIGH); // Clock high
        digitalWrite(clockPin, LOW);  // Clock low
    }
}

int main() {
    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "WiringPi setup failed!\n");
        return 1;
    }

