    while (1) {
        // Generate a random number between 0 and 9
        int randomNumber = rand() % 10;

        // Get the segment pattern for the random number
        unsigned char segmentPattern = digits[randomNumber];

        // Latch low to start sending data
        digitalWrite(LATCH_PIN, LOW);

        // Shift out the segment pattern
        shiftOut(DATA_PIN, CLOCK_PIN, segmentPattern);

        // Latch high to display the number
        digitalWrite(LATCH_PIN, HIGH);

        // Wait for 2 seconds
