#include <wiringPiSPI.h>

// MCP3008 defines
#define SPI_CHANNEL 0
#define SPI_SPEED 1000000 // 1MHz

// Function to read data from MCP3008
int read_mcp3008(int channel)
{
    uint8_t buffer[3];
    buffer[0] = 0x01; // Start bit
    buffer[1] = (0x08 | channel) << 4; // Single-ended mode, channel select
    buffer[2] = 0x00;

    wiringPiSPIDataRW(SPI_CHANNEL, buffer, 3);

    int adc_value = ((buffer[1] & 0x03) << 8) + buffer[2];
    return adc_value;
}

int main()
{
    // Initialize WiringPi
    if (wiringPiSetup() == -1)
    {
        fprintf(stderr, "WiringPi setup failed!\n");
        return 1;
