        buzzer_state = 1;
        printf("Motion detected! Buzzer ON\n");
    }
}

// Function to handle stop button interrupt (with debounce)
void stop_button_interrupt(int gpio, int level, unsigned int tick)
{
    unsigned int current_time = tick;
    unsigned int time_diff = current_time - last_interrupt_time;

    if (time_diff > DEBOUNCE_TIME * 1000) // Debounce check (microseconds)
    {
        if (level == 0) // Falling edge (button pressed)
        {
            gpioWrite(BUZZER_PIN, 0); // Turn off the buzzer
            buzzer_state = 0;
            printf("Buzzer OFF (button pressed)\n");
            last_interrupt_time = current_time;
        }
    }
}

